export const SECTION_11: LawSection = { id: 'ccyc-s11', lawId: 'codigo-civil-comercial', number: 'XI', name: 'Libro Tercero - Contratos en Particular II (Arts. 1381-1550)', articleStart: 1381, articleEnd: 1550, titles: [] };

export const ARTICLES_11: Article[] = [
  { id: 'ccyc-art-1381', lawId: 'codigo-civil-comercial', number: '1381', order: 1381, title: "Contenido", text: "Contenido. El contrato debe especificar la tasa de interés y cualquier precio, gasto, comisión y otras condiciones económicas a cargo del cliente. Si no determina la tasa de interés, es aplicable la nominal mínima y máxima, respectivamente, para las operaciones activas y pasivas promedio del sistema, publicadas por el Banco Central de la República Argentina a la fecha del desembolso o de la imposición. Las cláusulas de remisión a los usos para la determinación de las tasas de interés y de otros precios y condiciones contractuales se tienen por no escritas.", plainLanguageExplanation: "Establece el régimen de contenido. El contrato debe especificar la tasa de interés y cualquier precio, gasto, comisión y otras condiciones económicas a cargo del cliente.", practicalEffects: ['En la práctica, este artículo rige contenido. El contrato debe especificar la tasa de interés y cualquier precio, gasto, comisión y otras condiciones económicas a cargo del cliente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contenidoarticulo 1381'], segments: [], amendments: [] },
  { id: 'ccyc-art-1382', lawId: 'codigo-civil-comercial', number: '1382', order: 1382, title: "Información periódica", text: "Información periódica. El banco debe comunicar en forma clara, escrita o por medios electrónicos previamente aceptados por el cliente, al menos una vez al año, el desenvolvimiento de las operaciones correspondientes a contratos de plazo indeterminado o de plazo mayor a un año. Transcurridos sesenta días contados a partir de la recepción de la comunicación, la falta de oposición escrita por parte del cliente se entiende como aceptación de las operaciones informadas, sin perjuicio de las acciones previstas en los contratos de consumo. Igual regla se aplica a la finalización de todo contrato que prevea plazos para el cumplimiento.", plainLanguageExplanation: "Establece el régimen de información periódica. El banco debe comunicar en forma clara, escrita o por medios electrónicos previamente aceptados por el cliente, al menos una vez al año, el desenvolvimiento de las operaciones correspondientes a contratos de plazo indeterminado o de plazo mayor a un año.", practicalEffects: ['En la práctica, este artículo rige información periódica. El banco debe comunicar en forma clara, escrita o por medios electrónicos previamente aceptados por el cliente, al menos una vez al año, el desenvolvi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['informacin', 'peridica', 'articulo 1382'], segments: [], amendments: [] },
  { id: 'ccyc-art-1383', lawId: 'codigo-civil-comercial', number: '1383', order: 1383, title: "Rescisión", text: "Rescisión. El cliente tiene derecho, en cualquier momento, a rescindir un contrato por tiempo indeterminado sin penalidad ni gastos, excepto los devengados antes del ejercicio de este derecho. Parágrafo 2° Contratos bancarios con consumidores y usuarios", plainLanguageExplanation: "Establece el régimen de rescisión. El cliente tiene derecho, en cualquier momento, a rescindir un contrato por tiempo indeterminado sin penalidad ni gastos, excepto los devengados antes del ejercicio de este derecho.", practicalEffects: ['En la práctica, este artículo rige rescisión. El cliente tiene derecho, en cualquier momento, a rescindir un contrato por tiempo indeterminado sin penalidad ni gastos, excepto los devengados antes del ejercicio de este derecho.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rescisinarticulo 1383'], segments: [], amendments: [] },
  { id: 'ccyc-art-1384', lawId: 'codigo-civil-comercial', number: '1384', order: 1384, title: "Aplicación", text: "Aplicación. Las disposiciones relativas a los contratos de consumo son aplicables a los contratos bancarios de conformidad con lo dispuesto en el artículo 1093.", plainLanguageExplanation: "Establece el régimen de aplicación. Las disposiciones relativas a los contratos de consumo son aplicables a los contratos bancarios de conformidad con lo dispuesto en el artículo 1093.", practicalEffects: ['En la práctica, este artículo rige aplicación. Las disposiciones relativas a los contratos de consumo son aplicables a los contratos bancarios de conformidad con lo dispuesto en el artículo 1093.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacinarticulo 1384'], segments: [], amendments: [] },
  { id: 'ccyc-art-1385', lawId: 'codigo-civil-comercial', number: '1385', order: 1385, title: "Publicidad", text: "Publicidad. Los anuncios del banco deben contener en forma clara, concisa y con un ejemplo representativo, información sobre las operaciones que se proponen. En particular deben especificar: a) los montos mínimos y máximos de las operaciones individualmente consideradas; b) la tasa de interés y si es fija o variable; c) las tarifas por gastos y comisiones, con indicación de los supuestos y la periodicidad de su aplicación; d) el costo financiero total en las operaciones de crédito; e) la existencia de eventuales servicios accesorios para el otorgamiento del crédito o la aceptación de la inversión y los costos relativos a tales servicios; f) la duración propuesta del contrato.", plainLanguageExplanation: "Establece el régimen de publicidad. Los anuncios del banco deben contener en forma clara, concisa y con un ejemplo representativo, información sobre las operaciones que se proponen.", practicalEffects: ['En la práctica, este artículo rige publicidad. Los anuncios del banco deben contener en forma clara, concisa y con un ejemplo representativo, información sobre las operaciones que se proponen.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicidadarticulo 1385'], segments: [], amendments: [] },
  { id: 'ccyc-art-1386', lawId: 'codigo-civil-comercial', number: '1386', order: 1386, title: "Forma", text: "Forma. El contrato debe ser redactado por escrito en instrumentos que permitan al consumidor: a) obtener una copia; b) conservar la información que le sea entregada por el banco; c) acceder a la información por un período de tiempo adecuado a la naturaleza del contrato; d) reproducir la información archivada.", plainLanguageExplanation: "Establece el régimen de forma. El contrato debe ser redactado por escrito en instrumentos que permitan al consumidor: a) obtener una copia; b) conservar la información que le sea entregada por el banco; c) acceder a la información por un período de tiempo adecuado a la naturaleza del contrato; d) reproducir la", practicalEffects: ['En la práctica, este artículo rige forma. El contrato debe ser redactado por escrito en instrumentos que permitan al consumidor: a) obtener una copia; b) conservar la información que le sea en'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 1386'], segments: [], amendments: [] },
  { id: 'ccyc-art-1387', lawId: 'codigo-civil-comercial', number: '1387', order: 1387, title: "Obligaciones precontractuales", text: "Obligaciones precontractuales. Antes de vincular contractualmente al consumidor, el banco debe proveer información suficiente para que el cliente pueda confrontar las distintas ofertas de crédito existentes en el sistema, publicadas por el Banco Central de la República Argentina. Si el banco rechaza una solicitud de crédito por la información negativa registrada en una base de datos, debe informar al consumidor en forma inmediata y gratuita el resultado de la consulta y la fuente de donde la obtuvo.", plainLanguageExplanation: "Establece el régimen de obligaciones precontractuales. Antes de vincular contractualmente al consumidor, el banco debe proveer información suficiente para que el cliente pueda confrontar las distintas ofertas de crédito existentes en el sistema, publicadas por el Banco Central de la República Argentina.", practicalEffects: ['En la práctica, este artículo rige obligaciones precontractuales. Antes de vincular contractualmente al consumidor, el banco debe proveer información suficiente para que el cliente pueda confrontar las distintas ofer'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'precontractuales', 'articulo 1387'], segments: [], amendments: [] },
  { id: 'ccyc-art-1388', lawId: 'codigo-civil-comercial', number: '1388', order: 1388, title: "Contenido", text: "Contenido. Sin perjuicio de las condiciones establecidas para los contratos bancarios en general, ninguna suma puede ser exigida al consumidor si no se encuentra expresamente prevista en el contrato. En ningún caso pueden cargarse comisiones o costos por servicios no prestados efectivamente. Las cláusulas relativas a costos a cargo del consumidor que no están incluidas o que están incluidas incorrectamente en el costo financiero total publicitado o incorporado al documento contractual, se tienen por no escritas.", plainLanguageExplanation: "Establece el régimen de contenido. Sin perjuicio de las condiciones establecidas para los contratos bancarios en general, ninguna suma puede ser exigida al consumidor si no se encuentra expresamente prevista en el contrato.", practicalEffects: ['En la práctica, este artículo rige contenido. Sin perjuicio de las condiciones establecidas para los contratos bancarios en general, ninguna suma puede ser exigida al consumidor si no se encuentra expresamente prevista en el contrato.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contenidoarticulo 1388'], segments: [], amendments: [] },
  { id: 'ccyc-art-1389', lawId: 'codigo-civil-comercial', number: '1389', order: 1389, title: "Información en contratos de crédito", text: "Información en contratos de crédito. Son nulos los contratos de crédito que no contienen información relativa al tipo y partes del contrato, el importe total del financiamiento, el costo financiero total y las condiciones de desembolso y reembolso. SECCION 2ª Contratos en particular Parágrafo 1° Depósito bancario", plainLanguageExplanation: "Establece el régimen de información en contratos de crédito. Son nulos los contratos de crédito que no contienen información relativa al tipo y partes del contrato, el importe total del financiamiento, el costo financiero total y las condiciones de desembolso y reembolso.", practicalEffects: ['En la práctica, este artículo rige información en contratos de crédito. Son nulos los contratos de crédito que no contienen información relativa al tipo y partes del contrato, el importe total del financiamiento, el costo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['informacin', 'contratos', 'crdito', 'articulo 1389'], segments: [], amendments: [] },
  { id: 'ccyc-art-1390', lawId: 'codigo-civil-comercial', number: '1390', order: 1390, title: "Depósito en dinero", text: "Depósito en dinero. Hay depósito de dinero cuando el depositante transfiere la propiedad al banco depositario, quien tiene la obligación de restituirlo en la moneda de la misma especie, a simple requerimiento del depositante, o al vencimiento del término o del preaviso convencionalmente previsto.", plainLanguageExplanation: "Establece el régimen de depósito en dinero. Hay depósito de dinero cuando el depositante transfiere la propiedad al banco depositario, quien tiene la obligación de restituirlo en la moneda de la misma especie, a simple requerimiento del depositante, o al vencimiento del término o del preaviso convencionalmente previsto.", practicalEffects: ['En la práctica, este artículo rige depósito en dinero. Hay depósito de dinero cuando el depositante transfiere la propiedad al banco depositario, quien tiene la obligación de restituirlo en la moneda de la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['depsito', 'dinero', 'articulo 1390'], segments: [], amendments: [] },
  { id: 'ccyc-art-1391', lawId: 'codigo-civil-comercial', number: '1391', order: 1391, title: "Depósito a la vista", text: "Depósito a la vista. El depósito a la vista debe estar representado en un documento material o electrónico que refleje fielmente los movimientos y el saldo de la cuenta del cliente. El banco puede dejar sin efecto la constancia por él realizada que no corresponda a esa cuenta. Si el depósito está a nombre de dos o más personas, cualquiera de ellas puede disponerlo, aun en caso de muerte de una, excepto que se haya convenido lo contrario.", plainLanguageExplanation: "Establece el régimen de depósito a la vista. El depósito a la vista debe estar representado en un documento material o electrónico que refleje fielmente los movimientos y el saldo de la cuenta del cliente.", practicalEffects: ['En la práctica, este artículo rige depósito a la vista. El depósito a la vista debe estar representado en un documento material o electrónico que refleje fielmente los movimientos y el saldo de la cuenta del cliente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['depsito', 'vista', 'articulo 1391'], segments: [], amendments: [] },
  { id: 'ccyc-art-1392', lawId: 'codigo-civil-comercial', number: '1392', order: 1392, title: "Depósito a plazo", text: "Depósito a plazo. El depósito a plazo otorga al depositante el derecho a una remuneración si no retira la suma depositada antes del término o del preaviso convenidos. El banco debe extender un certificado transferible por endoso, excepto que se haya pactado lo contrario, en cuyo caso la transmisión sólo puede realizarse a través del contrato de cesión de derechos. Parágrafo 2° Cuenta corriente bancaria", plainLanguageExplanation: "Establece el régimen de depósito a plazo. El depósito a plazo otorga al depositante el derecho a una remuneración si no retira la suma depositada antes del término o del preaviso convenidos.", practicalEffects: ['En la práctica, este artículo rige depósito a plazo. El depósito a plazo otorga al depositante el derecho a una remuneración si no retira la suma depositada antes del término o del preaviso convenidos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['depsito', 'plazo', 'articulo 1392'], segments: [], amendments: [] },
  { id: 'ccyc-art-1393', lawId: 'codigo-civil-comercial', number: '1393', order: 1393, title: "Definición", text: "Definición. La cuenta corriente bancaria es el contrato por el cual el banco se compromete a inscribir diariamente, y por su orden, los créditos y débitos, de modo de mantener un saldo actualizado y en disponibilidad del cuentacorrentista y, en su caso, a prestar un servicio de caja.", plainLanguageExplanation: "Establece el régimen de definición. La cuenta corriente bancaria es el contrato por el cual el banco se compromete a inscribir diariamente, y por su orden, los créditos y débitos, de modo de mantener un saldo actualizado y en disponibilidad del cuentacorrentista y, en su caso, a prestar un servicio de caja.", practicalEffects: ['En la práctica, este artículo rige definición. La cuenta corriente bancaria es el contrato por el cual el banco se compromete a inscribir diariamente, y por su orden, los créditos y débitos, de mod'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1393'], segments: [], amendments: [] },
  { id: 'ccyc-art-1394', lawId: 'codigo-civil-comercial', number: '1394', order: 1394, title: "Otros servicios", text: "Otros servicios. El banco debe prestar los demás servicios relacionados con la cuenta que resulten de la convención, de las reglamentaciones, o de los usos y prácticas.", plainLanguageExplanation: "Establece el régimen de otros servicios. El banco debe prestar los demás servicios relacionados con la cuenta que resulten de la convención, de las reglamentaciones, o de los usos y prácticas.", practicalEffects: ['En la práctica, este artículo rige otros servicios. El banco debe prestar los demás servicios relacionados con la cuenta que resulten de la convención, de las reglamentaciones, o de los usos y prácticas'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['otros', 'servicios', 'articulo 1394'], segments: [], amendments: [] },
  { id: 'ccyc-art-1395', lawId: 'codigo-civil-comercial', number: '1395', order: 1395, title: "Créditos y débitos", text: "Créditos y débitos. Con sujeción a los pactos, los usos y la reglamentación: a) se acreditan en la cuenta los depósitos y remesas de dinero, el producto de la cobranza de títulos valores y los créditos otorgados por el banco para que el cuentacorrentista disponga de ellos; b) se debitan de la cuenta los retiros que haga el cuentacorrentista, los pagos o remesas que haga el banco por instrucciones de aquél, las comisiones, gastos e impuestos relativos a la cuenta y los cargos contra el cuentacorrentista que resulten de otros negocios que pueda tener con el banco. Los débitos pueden realizarse en descubierto.", plainLanguageExplanation: "Establece el régimen de créditos y débitos. Con sujeción a los pactos, los usos y la reglamentación: a) se acreditan en la cuenta los depósitos y remesas de dinero, el producto de la cobranza de títulos valores y los créditos otorgados por el banco para que el cuentacorrentista disponga de ellos; b) se debitan de la cuenta", practicalEffects: ['En la práctica, este artículo rige créditos y débitos. Con sujeción a los pactos, los usos y la reglamentación: a) se acreditan en la cuenta los depósitos y remesas de dinero, el producto de la cobranza de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['crditos', 'dbitos', 'articulo 1395'], segments: [], amendments: [] },
  { id: 'ccyc-art-1396', lawId: 'codigo-civil-comercial', number: '1396', order: 1396, title: "Instrumentación", text: "Instrumentación. Los créditos y débitos pueden efectuarse y las cuentas pueden ser llevadas por medios mecánicos, electrónicos, de computación u otros en las condiciones que establezca la reglamentación, la que debe determinar también la posibilidad de conexiones de redes en tiempo real y otras que sean pertinentes de acuerdo con los medios técnicos disponibles, en orden a la celeridad y seguridad de las transacciones.", plainLanguageExplanation: "Establece el régimen de instrumentación. Los créditos y débitos pueden efectuarse y las cuentas pueden ser llevadas por medios mecánicos, electrónicos, de computación u otros en las condiciones que establezca la reglamentación, la que debe determinar también la posibilidad de conexiones de redes en tiempo real y otras q", practicalEffects: ['En la práctica, este artículo rige instrumentación. Los créditos y débitos pueden efectuarse y las cuentas pueden ser llevadas por medios mecánicos, electrónicos, de computación u otros en las condicion'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['instrumentacinarticulo 1396'], segments: [], amendments: [] },
  { id: 'ccyc-art-1397', lawId: 'codigo-civil-comercial', number: '1397', order: 1397, title: "Servicio de cheques", text: "Servicio de cheques. Si el contrato incluye el servicio de cheques, el banco debe entregar al cuentacorrentista, a su solicitud, los formularios correspondientes.", plainLanguageExplanation: "Establece el régimen de servicio de cheques. Si el contrato incluye el servicio de cheques, el banco debe entregar al cuentacorrentista, a su solicitud, los formularios correspondientes.", practicalEffects: ['En la práctica, este artículo rige servicio de cheques. Si el contrato incluye el servicio de cheques, el banco debe entregar al cuentacorrentista, a su solicitud, los formularios correspondientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['servicio', 'cheques', 'articulo 1397'], segments: [], amendments: [] },
  { id: 'ccyc-art-1398', lawId: 'codigo-civil-comercial', number: '1398', order: 1398, title: "Intereses", text: "Intereses. El saldo deudor de la cuenta corriente genera intereses, que se capitalizan trimestralmente, excepto que lo contrario resulte de la reglamentación, de la convención o de los usos. Las partes pueden convenir que el saldo acreedor de la cuenta corriente genere intereses capitalizables en los períodos y a la tasa que libremente pacten.", plainLanguageExplanation: "Establece el régimen de intereses. El saldo deudor de la cuenta corriente genera intereses, que se capitalizan trimestralmente, excepto que lo contrario resulte de la reglamentación, de la convención o de los usos.", practicalEffects: ['En la práctica, este artículo rige intereses. El saldo deudor de la cuenta corriente genera intereses, que se capitalizan trimestralmente, excepto que lo contrario resulte de la reglamentación, de la convención o de los usos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interesesarticulo 1398'], segments: [], amendments: [] },
  { id: 'ccyc-art-1399', lawId: 'codigo-civil-comercial', number: '1399', order: 1399, title: "Solidaridad", text: "Solidaridad. En las cuentas a nombre de dos o más personas los titulares son solidariamente responsables frente al banco por los saldos que arrojen.", plainLanguageExplanation: "Establece el régimen de solidaridad. En las cuentas a nombre de dos o más personas los titulares son solidariamente responsables frente al banco por los saldos que arrojen.", practicalEffects: ['En la práctica, este artículo rige solidaridad. En las cuentas a nombre de dos o más personas los titulares son solidariamente responsables frente al banco por los saldos que arrojen.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['solidaridadarticulo 1399'], segments: [], amendments: [] },
  { id: 'ccyc-art-1400', lawId: 'codigo-civil-comercial', number: '1400', order: 1400, title: "Propiedad de los fondos", text: "Propiedad de los fondos. Excepto prueba en contrario, se presume que la propiedad de los fondos existentes en la cuenta abierta, conjunta o indistintamente, a nombre de más de una persona pertenece a los titulares por partes iguales.", plainLanguageExplanation: "Establece el régimen de propiedad de los fondos. Excepto prueba en contrario, se presume que la propiedad de los fondos existentes en la cuenta abierta, conjunta o indistintamente, a nombre de más de una persona pertenece a los titulares por partes iguales.", practicalEffects: ['En la práctica, este artículo rige propiedad de los fondos. Excepto prueba en contrario, se presume que la propiedad de los fondos existentes en la cuenta abierta, conjunta o indistintamente, a nombre de más de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['propiedad', 'fondos', 'articulo 1400'], segments: [], amendments: [] },
  { id: 'ccyc-art-1401', lawId: 'codigo-civil-comercial', number: '1401', order: 1401, title: "Reglas subsidiarias", text: "Reglas subsidiarias. Las reglas del mandato son aplicables a los encargos encomendados por el cuentacorrentista al banco. Si la operación debe realizarse en todo o en parte en una plaza en la que no existe casa del banco, él puede encomendarla a otro banco o a su corresponsal. El banco se exime del daño causado si la entidad a la que encomienda la tarea que lo causa es elegida por el cuentacorrentista.", plainLanguageExplanation: "Establece el régimen de reglas subsidiarias. Las reglas del mandato son aplicables a los encargos encomendados por el cuentacorrentista al banco.", practicalEffects: ['En la práctica, este artículo rige reglas subsidiarias. Las reglas del mandato son aplicables a los encargos encomendados por el cuentacorrentista al banco.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'subsidiarias', 'articulo 1401'], segments: [], amendments: [] },
  { id: 'ccyc-art-1402', lawId: 'codigo-civil-comercial', number: '1402', order: 1402, title: "Créditos o valores contra terceros", text: "Créditos o valores contra terceros. Los créditos o títulos valores recibidos al cobro por el banco se asientan en la cuenta una vez hechos efectivos. Si el banco lo asienta antes en la cuenta, puede excluir de la cuenta su valor mientras no haya percibido efectivamente el cobro.", plainLanguageExplanation: "Establece el régimen de créditos o valores contra terceros. Los créditos o títulos valores recibidos al cobro por el banco se asientan en la cuenta una vez hechos efectivos.", practicalEffects: ['En la práctica, este artículo rige créditos o valores contra terceros. Los créditos o títulos valores recibidos al cobro por el banco se asientan en la cuenta una vez hechos efectivos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['crditos', 'valores', 'contra', 'terceros', 'articulo 1402'], segments: [], amendments: [] },
  { id: 'ccyc-art-1403', lawId: 'codigo-civil-comercial', number: '1403', order: 1403, title: "Resúmenes", text: "Resúmenes. Excepto que resulten plazos distintos de las reglamentaciones, de la convención o de los usos: a) el banco debe remitir al cuentacorrentista dentro de los ocho días de finalizado cada mes, un extracto de los movimientos de cuenta y los saldos que resultan de cada crédito y débito; b) el resumen se presume aceptado si el cuentacorrentista no lo observa dentro de los diez días de su recepción o alega no haberlo recibido, pero deja transcurrir treinta días desde el vencimiento del plazo en que el banco debe enviarlo, sin reclamarlo. Las comunicaciones previstas en este artículo deben efectuarse en la forma que disponga la reglamentación, que puede considerar la utilización de medios mecánicos, electrónicos, de computación u otros.", plainLanguageExplanation: "Establece el régimen de resúmenes. Excepto que resulten plazos distintos de las reglamentaciones, de la convención o de los usos: a) el banco debe remitir al cuentacorrentista dentro de los ocho días de finalizado cada mes, un extracto de los movimientos de cuenta y los saldos que resultan de cada crédito y débito", practicalEffects: ['En la práctica, este artículo rige resúmenes. Excepto que resulten plazos distintos de las reglamentaciones, de la convención o de los usos: a) el banco debe remitir al cuentacorrentista dentro de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resmenesarticulo 1403'], segments: [], amendments: [] },
  { id: 'ccyc-art-1404', lawId: 'codigo-civil-comercial', number: '1404', order: 1404, title: "Cierre de cuenta", text: "Cierre de cuenta. La cuenta corriente se cierra: a) por decisión unilateral de cualquiera de las partes, previo aviso con una anticipación de diez días, excepto pacto en contrario; b) por quiebra, muerte o incapacidad del cuentacorrentista; c) por revocación de la autorización para funcionar, quiebra o liquidación del banco; d) por las demás causales que surjan de la reglamentación o de la convención.", plainLanguageExplanation: "Establece el régimen de cierre de cuenta. La cuenta corriente se cierra: a) por decisión unilateral de cualquiera de las partes, previo aviso con una anticipación de diez días, excepto pacto en contrario; b) por quiebra, muerte o incapacidad del cuentacorrentista; c) por revocación de la autorización para funcionar, quie", practicalEffects: ['En la práctica, este artículo rige cierre de cuenta. La cuenta corriente se cierra: a) por decisión unilateral de cualquiera de las partes, previo aviso con una anticipación de diez días, excepto pacto e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cierre', 'cuenta', 'articulo 1404'], segments: [], amendments: [] },
  { id: 'ccyc-art-1405', lawId: 'codigo-civil-comercial', number: '1405', order: 1405, title: "Compensación de saldos", text: "Compensación de saldos. Cuando el banco cierre más de una cuenta de un mismo titular, debe compensar sus saldos hasta su concurrencia, aunque sean expresados en distintas monedas.", plainLanguageExplanation: "Establece el régimen de compensación de saldos. Cuando el banco cierre más de una cuenta de un mismo titular, debe compensar sus saldos hasta su concurrencia, aunque sean expresados en distintas monedas.", practicalEffects: ['En la práctica, este artículo rige compensación de saldos. Cuando el banco cierre más de una cuenta de un mismo titular, debe compensar sus saldos hasta su concurrencia, aunque sean expresados en distintas mon'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['compensacin', 'saldos', 'articulo 1405'], segments: [], amendments: [] },
  { id: 'ccyc-art-1406', lawId: 'codigo-civil-comercial', number: '1406', order: 1406, title: "Ejecución de saldo", text: "Ejecución de saldo. Producido el cierre de una cuenta, e informado el cuentacorrentista, si el banco está autorizado a operar en la República puede emitir un título con eficacia ejecutiva. El documento debe ser firmado por dos personas, apoderadas del banco mediante escritura pública, en el que se debe indicar: a) el día de cierre de la cuenta; b) el saldo a dicha fecha; c) el medio por el que ambas circunstancias fueron comunicadas al cuentacorrentista. El banco es responsable por el perjuicio causado por la emisión o utilización indebida de dicho título.", plainLanguageExplanation: "Establece el régimen de ejecución de saldo. Producido el cierre de una cuenta, e informado el cuentacorrentista, si el banco está autorizado a operar en la República puede emitir un título con eficacia ejecutiva.", practicalEffects: ['En la práctica, este artículo rige ejecución de saldo. Producido el cierre de una cuenta, e informado el cuentacorrentista, si el banco está autorizado a operar en la República puede emitir un título con eficacia ejecutiva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejecucin', 'saldo', 'articulo 1406'], segments: [], amendments: [] },
  { id: 'ccyc-art-1407', lawId: 'codigo-civil-comercial', number: '1407', order: 1407, title: "Garantías", text: "Garantías. El saldo deudor de la cuenta corriente puede ser garantizado con hipoteca, prenda, fianza o cualquier otra clase de garantía. Parágrafo 3° Préstamo y descuento bancario", plainLanguageExplanation: "Establece el régimen de garantías. El saldo deudor de la cuenta corriente puede ser garantizado con hipoteca, prenda, fianza o cualquier otra clase de garantía.", practicalEffects: ['En la práctica, este artículo rige garantías. El saldo deudor de la cuenta corriente puede ser garantizado con hipoteca, prenda, fianza o cualquier otra clase de garantía.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garantasarticulo 1407'], segments: [], amendments: [] },
  { id: 'ccyc-art-1408', lawId: 'codigo-civil-comercial', number: '1408', order: 1408, title: "Préstamo bancario", text: "Préstamo bancario. El préstamo bancario es el contrato por el cual el banco se compromete a entregar una suma de dinero obligándose el prestatario a su devolución y al pago de los intereses en la moneda de la misma especie, conforme con lo pactado.", plainLanguageExplanation: "Establece el régimen de préstamo bancario. El préstamo bancario es el contrato por el cual el banco se compromete a entregar una suma de dinero obligándose el prestatario a su devolución y al pago de los intereses en la moneda de la misma especie, conforme con lo pactado.", practicalEffects: ['En la práctica, este artículo rige préstamo bancario. El préstamo bancario es el contrato por el cual el banco se compromete a entregar una suma de dinero obligándose el prestatario a su devolución y al p'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prstamo', 'bancario', 'articulo 1408'], segments: [], amendments: [] },
  { id: 'ccyc-art-1409', lawId: 'codigo-civil-comercial', number: '1409', order: 1409, title: "Descuento bancario", text: "Descuento bancario. El contrato de descuento bancario obliga al titular de un crédito contra terceros a cederlo a un banco, y a éste a anticiparle el importe del crédito, en la moneda de la misma especie, conforme con lo pactado. El banco tiene derecho a la restitución de las sumas anticipadas, aunque el descuento tenga lugar mediante endoso de letras de cambio, pagarés o cheques y haya ejercido contra el tercero los derechos y acciones derivados del título. Parágrafo 4° Apertura de crédito", plainLanguageExplanation: "Establece el régimen de descuento bancario. El contrato de descuento bancario obliga al titular de un crédito contra terceros a cederlo a un banco, y a éste a anticiparle el importe del crédito, en la moneda de la misma especie, conforme con lo pactado.", practicalEffects: ['En la práctica, este artículo rige descuento bancario. El contrato de descuento bancario obliga al titular de un crédito contra terceros a cederlo a un banco, y a éste a anticiparle el importe del crédito,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['descuento', 'bancario', 'articulo 1409'], segments: [], amendments: [] },
  { id: 'ccyc-art-1410', lawId: 'codigo-civil-comercial', number: '1410', order: 1410, title: "Definición", text: "Definición. En la apertura de crédito, el banco se obliga, a cambio de una remuneración en la moneda de la misma especie de la obligación principal, conforme con lo pactado, a mantener a disposición de otra persona un crédito de dinero, dentro del límite acordado y por un tiempo fijo o indeterminado; si no se expresa la duración de la disponibilidad, se considera de plazo indeterminado.", plainLanguageExplanation: "Establece el régimen de definición. En la apertura de crédito, el banco se obliga, a cambio de una remuneración en la moneda de la misma especie de la obligación principal, conforme con lo pactado, a mantener a disposición de otra persona un crédito de dinero, dentro del límite acordado y por un tiempo fijo o indet", practicalEffects: ['En la práctica, este artículo rige definición. En la apertura de crédito, el banco se obliga, a cambio de una remuneración en la moneda de la misma especie de la obligación principal, conforme con'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1410'], segments: [], amendments: [] },
  { id: 'ccyc-art-1411', lawId: 'codigo-civil-comercial', number: '1411', order: 1411, title: "Disponibilidad", text: "Disponibilidad. La utilización del crédito hasta el límite acordado extingue la obligación del banco, excepto que se pacte que los reembolsos efectuados por el acreditado sean disponibles durante la vigencia del contrato o hasta el preaviso de vencimiento.", plainLanguageExplanation: "Establece el régimen de disponibilidad. La utilización del crédito hasta el límite acordado extingue la obligación del banco, excepto que se pacte que los reembolsos efectuados por el acreditado sean disponibles durante la vigencia del contrato o hasta el preaviso de vencimiento.", practicalEffects: ['En la práctica, este artículo rige disponibilidad. La utilización del crédito hasta el límite acordado extingue la obligación del banco, excepto que se pacte que los reembolsos efectuados por el acredi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disponibilidadarticulo 1411'], segments: [], amendments: [] },
  { id: 'ccyc-art-1412', lawId: 'codigo-civil-comercial', number: '1412', order: 1412, title: "Carácter de la disponibilidad", text: "Carácter de la disponibilidad. La disponibilidad no puede ser invocada por terceros, no es embargable, ni puede ser utilizada para compensar cualquier otra obligación del acreditado. Parágrafo 5° Servicio de caja de seguridad", plainLanguageExplanation: "Establece el régimen de carácter de la disponibilidad. La disponibilidad no puede ser invocada por terceros, no es embargable, ni puede ser utilizada para compensar cualquier otra obligación del acreditado.", practicalEffects: ['En la práctica, este artículo rige carácter de la disponibilidad. La disponibilidad no puede ser invocada por terceros, no es embargable, ni puede ser utilizada para compensar cualquier otra obligación del acreditado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carcter', 'disponibilidad', 'articulo 1412'], segments: [], amendments: [] },
  { id: 'ccyc-art-1413', lawId: 'codigo-civil-comercial', number: '1413', order: 1413, title: "Obligaciones a cargo de las partes", text: "Obligaciones a cargo de las partes. El prestador de una caja de seguridad responde frente al usuario por la idoneidad de la custodia de los locales, la integridad de las cajas y el contenido de ellas, conforme con lo pactado y las expectativas creadas en el usuario. No responde por caso fortuito externo a su actividad, ni por vicio propio de las cosas guardadas.", plainLanguageExplanation: "Establece el régimen de obligaciones a cargo de las partes. El prestador de una caja de seguridad responde frente al usuario por la idoneidad de la custodia de los locales, la integridad de las cajas y el contenido de ellas, conforme con lo pactado y las expectativas creadas en el usuario.", practicalEffects: ['En la práctica, este artículo rige obligaciones a cargo de las partes. El prestador de una caja de seguridad responde frente al usuario por la idoneidad de la custodia de los locales, la integridad de las cajas y el conte'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'cargo', 'partes', 'articulo 1413'], segments: [], amendments: [] },
  { id: 'ccyc-art-1414', lawId: 'codigo-civil-comercial', number: '1414', order: 1414, title: "Límites", text: "Límites. La cláusula que exime de responsabilidad al prestador se tiene por no escrita. Es válida la cláusula de limitación de la responsabilidad del prestador hasta un monto máximo sólo si el usuario es debidamente informado y el límite no importa una desnaturalización de las obligaciones del prestador.", plainLanguageExplanation: "Establece el régimen de límites. La cláusula que exime de responsabilidad al prestador se tiene por no escrita.", practicalEffects: ['En la práctica, este artículo rige límites. La cláusula que exime de responsabilidad al prestador se tiene por no escrita.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lmitesarticulo 1414'], segments: [], amendments: [] },
  { id: 'ccyc-art-1415', lawId: 'codigo-civil-comercial', number: '1415', order: 1415, title: "Prueba de contenido", text: "Prueba de contenido. La prueba del contenido de la caja de seguridad puede hacerse por cualquier medio.", plainLanguageExplanation: "Establece el régimen de prueba de contenido. La prueba del contenido de la caja de seguridad puede hacerse por cualquier medio.", practicalEffects: ['En la práctica, este artículo rige prueba de contenido. La prueba del contenido de la caja de seguridad puede hacerse por cualquier medio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prueba', 'contenido', 'articulo 1415'], segments: [], amendments: [] },
  { id: 'ccyc-art-1416', lawId: 'codigo-civil-comercial', number: '1416', order: 1416, title: "Pluralidad de usuarios", text: "Pluralidad de usuarios. Si los usuarios son dos o más personas, cualquiera de ellas, indistintamente, tiene derecho a acceder a la caja.", plainLanguageExplanation: "Establece el régimen de pluralidad de usuarios. Si los usuarios son dos o más personas, cualquiera de ellas, indistintamente, tiene derecho a acceder a la caja.", practicalEffects: ['En la práctica, este artículo rige pluralidad de usuarios. Si los usuarios son dos o más personas, cualquiera de ellas, indistintamente, tiene derecho a acceder a la caja.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pluralidad', 'usuarios', 'articulo 1416'], segments: [], amendments: [] },
  { id: 'ccyc-art-1417', lawId: 'codigo-civil-comercial', number: '1417', order: 1417, title: "Retiro de los efectos", text: "Retiro de los efectos. Vencido el plazo o resuelto el contrato por falta de pago o por cualquier otra causa convencionalmente prevista, el prestador debe dar a la otra parte aviso fe-haciente del vencimiento operado, con el apercibimiento de proceder, pasados treinta días del aviso, a la apertura forzada de la caja ante escribano público. En su caso, el prestador debe notificar al usuario la realización de la apertura forzada de la caja poniendo a su disposición su contenido, previo pago de lo adeudado, por el plazo de tres meses; vencido dicho plazo y no habiéndose presentado el usuario, puede cobrar el precio impago de los fondos hallados en la caja. En su defecto puede proceder a la venta de los efectos necesarios para cubrir lo adeudado en la forma prevista por el artículo 2229, dando aviso al usuario. El producido de la venta se aplica al pago de lo adeudado. Los bienes remanentes deben ser consignados judicialmente por alguna de las vías previstas en este Código. Parágrafo 6° Custodia de títulos", plainLanguageExplanation: "Establece el régimen de retiro de los efectos. Vencido el plazo o resuelto el contrato por falta de pago o por cualquier otra causa convencionalmente prevista, el prestador debe dar a la otra parte aviso fe-haciente del vencimiento operado, con el apercibimiento de proceder, pasados treinta días del aviso, a la apertura forza", practicalEffects: ['En la práctica, este artículo rige retiro de los efectos. Vencido el plazo o resuelto el contrato por falta de pago o por cualquier otra causa convencionalmente prevista, el prestador debe dar a la otra parte'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retiro', 'efectos', 'articulo 1417'], segments: [], amendments: [] },
  { id: 'ccyc-art-1418', lawId: 'codigo-civil-comercial', number: '1418', order: 1418, title: "Obligaciones a cargo de las partes", text: "Obligaciones a cargo de las partes. El banco que asume a cambio de una remuneración la custodia de títulos en administración debe proceder a su guarda, gestionar el cobro de los intereses o los dividendos y los reembolsos del capital por cuenta del depositante y, en general, proveer la tutela de los derechos inherentes a los títulos.", plainLanguageExplanation: "Establece el régimen de obligaciones a cargo de las partes. El banco que asume a cambio de una remuneración la custodia de títulos en administración debe proceder a su guarda, gestionar el cobro de los intereses o los dividendos y los reembolsos del capital por cuenta del depositante y, en general, proveer la tutela de los derechos inhere", practicalEffects: ['En la práctica, este artículo rige obligaciones a cargo de las partes. El banco que asume a cambio de una remuneración la custodia de títulos en administración debe proceder a su guarda, gestionar el cobro de los interese'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'cargo', 'partes', 'articulo 1418'], segments: [], amendments: [] },
  { id: 'ccyc-art-1419', lawId: 'codigo-civil-comercial', number: '1419', order: 1419, title: "Omisión de instrucciones", text: "Omisión de instrucciones. La omisión de instrucciones del depositante no libera al banco del ejercicio de los derechos emergentes de los títulos.", plainLanguageExplanation: "Establece el régimen de omisión de instrucciones. La omisión de instrucciones del depositante no libera al banco del ejercicio de los derechos emergentes de los títulos.", practicalEffects: ['En la práctica, este artículo rige omisión de instrucciones. La omisión de instrucciones del depositante no libera al banco del ejercicio de los derechos emergentes de los títulos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['omisin', 'instrucciones', 'articulo 1419'], segments: [], amendments: [] },
  { id: 'ccyc-art-1420', lawId: 'codigo-civil-comercial', number: '1420', order: 1420, title: "Disposición", text: "Disposición. Autorización otorgada al banco. En el depósito de títulos valores es válida la autorización otorgada al banco para disponer de ellos, obligándose a entregar otros del mismo género, calidad y cantidad, cuando se hubiese convenido en forma expresa y las características de los títulos lo permita. Si la restitución resulta de cumplimiento imposible, el banco debe cancelar la obligación con el pago de una suma de dinero equivalente al valor de los títulos al momento en que debe hacerse la devolución. CAPITULO 13 Contrato de factoraje", plainLanguageExplanation: "Establece el régimen de disposición. Autorización otorgada al banco.", practicalEffects: ['En la práctica, este artículo rige disposición. Autorización otorgada al banco.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposicinarticulo 1420'], segments: [], amendments: [] },
  { id: 'ccyc-art-1421', lawId: 'codigo-civil-comercial', number: '1421', order: 1421, title: "Definición", text: "Definición. Hay contrato de factoraje cuando una de las partes, denominada factor, se obliga a adquirir por un precio en dinero determinado o determinable los créditos originados en el giro comercial de la otra, denominada factoreado, pudiendo otorgar anticipo sobre tales créditos asumiendo o no los riesgos.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de factoraje cuando una de las partes, denominada factor, se obliga a adquirir por un precio en dinero determinado o determinable los créditos originados en el giro comercial de la otra, denominada factoreado, pudiendo otorgar anticipo sobre tales créditos asumiendo", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de factoraje cuando una de las partes, denominada factor, se obliga a adquirir por un precio en dinero determinado o determinable los cré'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1421'], segments: [], amendments: [] },
  { id: 'ccyc-art-1422', lawId: 'codigo-civil-comercial', number: '1422', order: 1422, title: "Otros servicios", text: "Otros servicios. La adquisición puede ser complementada con servicios de administración y gestión de cobranza, asistencia técnica, comercial o administrativa respecto de los créditos cedidos.", plainLanguageExplanation: "Establece el régimen de otros servicios. La adquisición puede ser complementada con servicios de administración y gestión de cobranza, asistencia técnica, comercial o administrativa respecto de los créditos cedidos.", practicalEffects: ['En la práctica, este artículo rige otros servicios. La adquisición puede ser complementada con servicios de administración y gestión de cobranza, asistencia técnica, comercial o administrativa respecto'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['otros', 'servicios', 'articulo 1422'], segments: [], amendments: [] },
  { id: 'ccyc-art-1423', lawId: 'codigo-civil-comercial', number: '1423', order: 1423, title: "Créditos que puede ceder el factoreado", text: "Créditos que puede ceder el factoreado. Son válidas las cesiones globales de parte o todos los créditos del factoreado, tanto los existentes como los futuros, siempre que estos últimos sean determinables.", plainLanguageExplanation: "Establece el régimen de créditos que puede ceder el factoreado. Son válidas las cesiones globales de parte o todos los créditos del factoreado, tanto los existentes como los futuros, siempre que estos últimos sean determinables.", practicalEffects: ['En la práctica, este artículo rige créditos que puede ceder el factoreado. Son válidas las cesiones globales de parte o todos los créditos del factoreado, tanto los existentes como los futuros, siempre que estos últimos sean'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['crditos', 'puede', 'ceder', 'factoreado', 'articulo 1423'], segments: [], amendments: [] },
  { id: 'ccyc-art-1424', lawId: 'codigo-civil-comercial', number: '1424', order: 1424, title: "Contrato", text: "Contrato. Elementos que debe incluir. El contrato debe incluir la relación de los derechos de crédito que se transmiten, la identificación del factor y factoreado y los datos necesarios para identificar los documentos representativos de los derechos de crédito, sus importes y sus fechas de emisión y vencimiento o los elementos que permitan su identificación cuando el factoraje es determinable.", plainLanguageExplanation: "Establece el régimen de contrato. Elementos que debe incluir.", practicalEffects: ['En la práctica, este artículo rige contrato. Elementos que debe incluir.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratoarticulo 1424'], segments: [], amendments: [] },
  { id: 'ccyc-art-1425', lawId: 'codigo-civil-comercial', number: '1425', order: 1425, title: "Efecto del contrato", text: "Efecto del contrato. El documento contractual es título suficiente de transmisión de los derechos cedidos.", plainLanguageExplanation: "Establece el régimen de efecto del contrato. El documento contractual es título suficiente de transmisión de los derechos cedidos.", practicalEffects: ['En la práctica, este artículo rige efecto del contrato. El documento contractual es título suficiente de transmisión de los derechos cedidos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efecto', 'contrato', 'articulo 1425'], segments: [], amendments: [] },
  { id: 'ccyc-art-1426', lawId: 'codigo-civil-comercial', number: '1426', order: 1426, title: "Garantía y aforos", text: "Garantía y aforos. Las garantías reales y personales y la retención anticipada de un porcentaje del crédito cedido para garantizar su incobrabilidad o aforo son válidos y subsisten hasta la extinción de las obligaciones del factoreado.", plainLanguageExplanation: "Establece el régimen de garantía y aforos. Las garantías reales y personales y la retención anticipada de un porcentaje del crédito cedido para garantizar su incobrabilidad o aforo son válidos y subsisten hasta la extinción de las obligaciones del factoreado.", practicalEffects: ['En la práctica, este artículo rige garantía y aforos. Las garantías reales y personales y la retención anticipada de un porcentaje del crédito cedido para garantizar su incobrabilidad o aforo son válidos'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garanta', 'aforos', 'articulo 1426'], segments: [], amendments: [] },
  { id: 'ccyc-art-1427', lawId: 'codigo-civil-comercial', number: '1427', order: 1427, title: "Imposibilidad del cobro del derecho de crédito cedido", text: "Imposibilidad del cobro del derecho de crédito cedido. Cuando el cobro del derecho de crédito cedido no sea posible por una razón que tenga su causa en el acto jurídico que le dio origen, el factoreado responde por la pérdida de valor de los derechos del crédito cedido, aun cuando el factoraje se haya celebrado sin garantía o recurso.", plainLanguageExplanation: "Establece el régimen de imposibilidad del cobro del derecho de crédito cedido. Cuando el cobro del derecho de crédito cedido no sea posible por una razón que tenga su causa en el acto jurídico que le dio origen, el factoreado responde por la pérdida de valor de los derechos del crédito cedido, aun cuando el factoraje se haya celebrado sin garantía o recurso", practicalEffects: ['En la práctica, este artículo rige imposibilidad del cobro del derecho de crédito cedido. Cuando el cobro del derecho de crédito cedido no sea posible por una razón que tenga su causa en el acto jurídico que le dio origen, el factoreado res'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imposibilidad', 'cobro', 'derecho', 'crdito', 'cedido', 'articulo 1427'], segments: [], amendments: [] },
  { id: 'ccyc-art-1428', lawId: 'codigo-civil-comercial', number: '1428', order: 1428, title: "Notificación al deudor cedido", text: "Notificación al deudor cedido. La transmisión de los derechos del crédito cedido debe ser notificada al deudor cedido por cualquier medio que evidencie razonablemente la recepción por parte de éste. CAPITULO 14 Contratos celebrados en bolsa o mercado de comercio", plainLanguageExplanation: "Establece el régimen de notificación al deudor cedido. La transmisión de los derechos del crédito cedido debe ser notificada al deudor cedido por cualquier medio que evidencie razonablemente la recepción por parte de éste.", practicalEffects: ['En la práctica, este artículo rige notificación al deudor cedido. La transmisión de los derechos del crédito cedido debe ser notificada al deudor cedido por cualquier medio que evidencie razonablemente la recepción por parte de éste.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['notificacin', 'deudor', 'cedido', 'articulo 1428'], segments: [], amendments: [] },
  { id: 'ccyc-art-1429', lawId: 'codigo-civil-comercial', number: '1429', order: 1429, title: "Normas aplicables", text: "Normas aplicables. Los contratos celebrados en una bolsa o mercado de comercio, de valores o de productos, en tanto éstos sean autorizados y operen bajo contralor estatal, se rigen por las normas dictadas por sus autoridades y aprobadas por el organismo de control. Estas normas pueden prever la liquidación del contrato por diferencia; regular las operaciones y contratos derivados; fijar garantías, márgenes y otras seguridades; establecer la determinación diaria o periódica de las posiciones de las partes y su liquidación ante eventos como el concurso, la quiebra o la muerte de una de ellas, la compensación y el establecimiento de un saldo neto de las operaciones entre las mismas partes y los demás aspectos necesarios para su operatividad. CAPITULO 15 Cuenta corriente", plainLanguageExplanation: "Establece el régimen de normas aplicables. Los contratos celebrados en una bolsa o mercado de comercio, de valores o de productos, en tanto éstos sean autorizados y operen bajo contralor estatal, se rigen por las normas dictadas por sus autoridades y aprobadas por el organismo de control.", practicalEffects: ['En la práctica, este artículo rige normas aplicables. Los contratos celebrados en una bolsa o mercado de comercio, de valores o de productos, en tanto éstos sean autorizados y operen bajo contralor estata'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'aplicables', 'articulo 1429'], segments: [], amendments: [] },
  { id: 'ccyc-art-1430', lawId: 'codigo-civil-comercial', number: '1430', order: 1430, title: "Definición", text: "Definición. Cuenta corriente es el contrato por el cual dos partes se comprometen a inscribir en una cuenta las remesas recíprocas que se efectúen y se obligan a no exigir ni disponer de los créditos resultantes de ellas hasta el final de un período, a cuyo vencimiento se compensan, haciéndose exigible y disponible el saldo que resulte.", plainLanguageExplanation: "Establece el régimen de definición. Cuenta corriente es el contrato por el cual dos partes se comprometen a inscribir en una cuenta las remesas recíprocas que se efectúen y se obligan a no exigir ni disponer de los créditos resultantes de ellas hasta el final de un período, a cuyo vencimiento se compensan, haciéndo", practicalEffects: ['En la práctica, este artículo rige definición. Cuenta corriente es el contrato por el cual dos partes se comprometen a inscribir en una cuenta las remesas recíprocas que se efectúen y se obligan a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1430'], segments: [], amendments: [] },
  { id: 'ccyc-art-1431', lawId: 'codigo-civil-comercial', number: '1431', order: 1431, title: "Contenido", text: "Contenido. Todos los créditos entre las partes resultantes de títulos valores o de relaciones contractuales posteriores al contrato se comprenden en la cuenta corriente, excepto estipulación en contrario. No pueden incorporarse a una cuenta corriente los créditos no compensables ni los ilíquidos o litigiosos.", plainLanguageExplanation: "Establece el régimen de contenido. Todos los créditos entre las partes resultantes de títulos valores o de relaciones contractuales posteriores al contrato se comprenden en la cuenta corriente, excepto estipulación en contrario.", practicalEffects: ['En la práctica, este artículo rige contenido. Todos los créditos entre las partes resultantes de títulos valores o de relaciones contractuales posteriores al contrato se comprenden en la cuenta corriente, excepto estipulación en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contenidoarticulo 1431'], segments: [], amendments: [] },
  { id: 'ccyc-art-1432', lawId: 'codigo-civil-comercial', number: '1432', order: 1432, title: "Plazos", text: "Plazos. Excepto convención o uso en contrario, se entiende que: a) los períodos son trimestrales, computándose el primero desde la fecha de celebración del contrato; b) el contrato no tiene plazo determinado. En este caso cualquiera de las partes puede rescindirlo otorgando un preaviso no menor a diez días a la otra por medio fehaciente, a cuyo vencimiento se produce el cierre, la compensación y el saldo de la cuenta; pero éste no puede exigirse antes de la fecha en que debe finalizar el período que se encuentra en curso al emitirse el preaviso; c) si el contrato tiene plazo determinado, se renueva por tácita reconducción. Cualquiera de las partes puede avisar con anticipación de diez días al vencimiento, su decisión de no continuarlo o el ejercicio del derecho que se indica en el inciso b), parte final, de este artículo, después del vencimiento del plazo original del contrato; d) si el contrato continúa o se renueva después de un cierre, el saldo de la remesa anterior es considerado la primera remesa del nuevo período, excepto que lo contrario resulte de una expresa manifestación de la parte que lleva la cuenta contenida en la comunicación del resumen y saldo del período, o de la otra, dentro del plazo del artículo 1438, primer párrafo.", plainLanguageExplanation: "Establece el régimen de plazos. Excepto convención o uso en contrario, se entiende que: a) los períodos son trimestrales, computándose el primero desde la fecha de celebración del contrato; b) el contrato no tiene plazo determinado.", practicalEffects: ['En la práctica, este artículo rige plazos. Excepto convención o uso en contrario, se entiende que: a) los períodos son trimestrales, computándose el primero desde la fecha de celebración del contrato; b) el contrato no tiene plazo determinado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazosarticulo 1432'], segments: [], amendments: [] },
  { id: 'ccyc-art-1433', lawId: 'codigo-civil-comercial', number: '1433', order: 1433, title: "Intereses, comisiones y gastos", text: "Intereses, comisiones y gastos. Excepto pacto en contrario, se entiende que: a) las remesas devengan intereses a la tasa pactada o, en su defecto, a la tasa de uso y a falta de ésta a la tasa legal; b) el saldo se considera capital productivo de intereses, aplicándose la tasa según el inciso a); c) las partes pueden convenir la capitalización de intereses en plazos inferiores al de un período; d) se incluyen en la cuenta, como remesas, las comisiones y gastos vinculados a las operaciones inscriptas.", plainLanguageExplanation: "Establece el régimen de intereses, comisiones y gastos. Excepto pacto en contrario, se entiende que: a) las remesas devengan intereses a la tasa pactada o, en su defecto, a la tasa de uso y a falta de ésta a la tasa legal; b) el saldo se considera capital productivo de intereses, aplicándose la tasa según el inciso a); c) las partes p", practicalEffects: ['En la práctica, este artículo rige intereses, comisiones y gastos. Excepto pacto en contrario, se entiende que: a) las remesas devengan intereses a la tasa pactada o, en su defecto, a la tasa de uso y a falta de ésta'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intereses', 'comisiones', 'gastos', 'articulo 1433'], segments: [], amendments: [] },
  { id: 'ccyc-art-1434', lawId: 'codigo-civil-comercial', number: '1434', order: 1434, title: "Garantías de créditos incorporados", text: "Garantías de créditos incorporados. Las garantías reales o personales de cada crédito incorporado se trasladan al saldo de cuenta, en tanto el garante haya prestado su previa aceptación.", plainLanguageExplanation: "Establece el régimen de garantías de créditos incorporados. Las garantías reales o personales de cada crédito incorporado se trasladan al saldo de cuenta, en tanto el garante haya prestado su previa aceptación.", practicalEffects: ['En la práctica, este artículo rige garantías de créditos incorporados. Las garantías reales o personales de cada crédito incorporado se trasladan al saldo de cuenta, en tanto el garante haya prestado su previa aceptación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garantas', 'crditos', 'incorporados', 'articulo 1434'], segments: [], amendments: [] },
  { id: 'ccyc-art-1435', lawId: 'codigo-civil-comercial', number: '1435', order: 1435, title: "Cláusula 'salvo encaje'", text: "Cláusula 'salvo encaje'. Excepto convención en contrario, la inclusión de un crédito contra un tercero en la cuenta corriente, se entiende efectuada con la cláusula 'salvo encaje'. Si el crédito no es satisfecho a su vencimiento, o antes al hacerse exigible contra cualquier obligado, el que recibe la remesa puede, a su elección, ejercer por sí la acción para el cobro o eliminar la partida de la cuenta, con reintegro de los derechos e instrumentos a la otra parte. Puede eliminarse la partida de la cuenta aun después de haber ejercido las acciones contra el deudor, en la medida en que el crédito y sus accesorios permanecen impagos. La eliminación de la partida de la cuenta o su contra asiento no puede efectuarse si el cuentacorrentista receptor ha perjudicado el crédito o el título valor remitido.", plainLanguageExplanation: "Establece el régimen de cláusula 'salvo encaje'. Excepto convención en contrario, la inclusión de un crédito contra un tercero en la cuenta corriente, se entiende efectuada con la cláusula 'salvo encaje'.", practicalEffects: ['En la práctica, este artículo rige cláusula \'salvo encaje\'. Excepto convención en contrario, la inclusión de un crédito contra un tercero en la cuenta corriente, se entiende efectuada con la cláusula \'salvo encaje\'.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusula', 'salvo', 'encaje', 'articulo 1435'], segments: [], amendments: [] },
  { id: 'ccyc-art-1436', lawId: 'codigo-civil-comercial', number: '1436', order: 1436, title: "Embargo", text: "Embargo. El embargo del saldo eventual de la cuenta por un acreedor de uno de los cuentacorrentistas, impide al otro aplicar nuevas remesas que perjudiquen el derecho del embargante, desde que ha sido notificado de la medida. No se consideran nuevas remesas las que resulten de derechos ya existentes al momento del embargo, aun cuando no se hayan anotado efectivamente en las cuentas de las partes. El cuentacorrentista notificado debe hacer saber al otro el embargo por medio fehaciente y queda facultado para rescindir el contrato.", plainLanguageExplanation: "Establece el régimen de embargo. El embargo del saldo eventual de la cuenta por un acreedor de uno de los cuentacorrentistas, impide al otro aplicar nuevas remesas que perjudiquen el derecho del embargante, desde que ha sido notificado de la medida.", practicalEffects: ['En la práctica, este artículo rige embargo. El embargo del saldo eventual de la cuenta por un acreedor de uno de los cuentacorrentistas, impide al otro aplicar nuevas remesas que perjudiquen el'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['embargoarticulo 1436'], segments: [], amendments: [] },
  { id: 'ccyc-art-1437', lawId: 'codigo-civil-comercial', number: '1437', order: 1437, title: "Ineficacia", text: "Ineficacia. La inclusión de un crédito en una cuenta corriente no impide el ejercicio de las acciones o de las excepciones que tiendan a la ineficacia del acto del que deriva. Declarada la ineficacia, el crédito debe eliminarse de la cuenta.", plainLanguageExplanation: "Establece el régimen de ineficacia. La inclusión de un crédito en una cuenta corriente no impide el ejercicio de las acciones o de las excepciones que tiendan a la ineficacia del acto del que deriva.", practicalEffects: ['En la práctica, este artículo rige ineficacia. La inclusión de un crédito en una cuenta corriente no impide el ejercicio de las acciones o de las excepciones que tiendan a la ineficacia del acto del que deriva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ineficaciaarticulo 1437'], segments: [], amendments: [] },
  { id: 'ccyc-art-1438', lawId: 'codigo-civil-comercial', number: '1438', order: 1438, title: "Resúmenes de cuenta", text: "Resúmenes de cuenta. Aprobación. Los resúmenes de cuenta que una parte reciba de la otra se presumen aceptados si no los observa dentro del plazo de diez días de la recepción o del que resulte de la convención o de los usos. Las observaciones se resuelven por el procedimiento más breve que prevea la ley local.", plainLanguageExplanation: "Establece el régimen de resúmenes de cuenta. Aprobación.", practicalEffects: ['En la práctica, este artículo rige resúmenes de cuenta. Aprobación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resmenes', 'cuenta', 'articulo 1438'], segments: [], amendments: [] },
  { id: 'ccyc-art-1439', lawId: 'codigo-civil-comercial', number: '1439', order: 1439, title: "Garantías", text: "Garantías. El saldo de la cuenta corriente puede ser garantizado con hipoteca, prenda, fianza o cualquier otra garantía.", plainLanguageExplanation: "Establece el régimen de garantías. El saldo de la cuenta corriente puede ser garantizado con hipoteca, prenda, fianza o cualquier otra garantía.", practicalEffects: ['En la práctica, este artículo rige garantías. El saldo de la cuenta corriente puede ser garantizado con hipoteca, prenda, fianza o cualquier otra garantía.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garantasarticulo 1439'], segments: [], amendments: [] },
  { id: 'ccyc-art-1440', lawId: 'codigo-civil-comercial', number: '1440', order: 1440, title: "Cobro ejecutivo del saldo", text: "Cobro ejecutivo del saldo. El cobro del saldo de la cuenta corriente puede demandarse por vía ejecutiva, la que queda expedita en cualquiera de los siguientes casos: a) si el resumen de cuenta en el que consta el saldo está suscripto con firma del deudor certificada por escribano o judicialmente reconocida. El reconocimiento se debe ajustar a las normas procesales locales y puede ser obtenido en forma ficta; b) si el resumen está acompañado de un saldo certificado por contador público y notificado mediante acto notarial en el domicilio contractual, fijándose la sede del registro del escribano para la recepción de observaciones en el plazo del artículo 1438. En este caso, el título ejecutivo queda configurado por el certificado notarial que acompaña el acta de notificación, la certificación de contador y la constancia del escribano de no haberse recibido observaciones en tiempo.", plainLanguageExplanation: "Establece el régimen de cobro ejecutivo del saldo. El cobro del saldo de la cuenta corriente puede demandarse por vía ejecutiva, la que queda expedita en cualquiera de los siguientes casos: a) si el resumen de cuenta en el que consta el saldo está suscripto con firma del deudor certificada por escribano o judicialmente reconocida.", practicalEffects: ['En la práctica, este artículo rige cobro ejecutivo del saldo. El cobro del saldo de la cuenta corriente puede demandarse por vía ejecutiva, la que queda expedita en cualquiera de los siguientes casos: a) si el re'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cobro', 'ejecutivo', 'saldo', 'articulo 1440'], segments: [], amendments: [] },
  { id: 'ccyc-art-1441', lawId: 'codigo-civil-comercial', number: '1441', order: 1441, title: "Extinción del contrato", text: "Extinción del contrato. Son medios especiales de extinción del contrato de cuenta corriente: a) la quiebra, la muerte o la incapacidad de cualquiera de las partes; b) el vencimiento del plazo o la rescisión, según lo dispuesto en el artículo 1432; c) en el caso previsto en el artículo 1436; d) de pleno derecho, pasados dos períodos completos o el lapso de un año, el que fuere menor, sin que las partes hubieren efectuado ninguna remesa con aplicación al contrato, excepto pacto en contrario; e) por las demás causales previstas en el contrato o en leyes particulares. CAPITULO 16 Contratos asociativos SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de extinción del contrato. Son medios especiales de extinción del contrato de cuenta corriente: a) la quiebra, la muerte o la incapacidad de cualquiera de las partes; b) el vencimiento del plazo o la rescisión, según lo dispuesto en el artículo 1432; c) en el caso previsto en el artículo 1436; d) de pleno", practicalEffects: ['En la práctica, este artículo rige extinción del contrato. Son medios especiales de extinción del contrato de cuenta corriente: a) la quiebra, la muerte o la incapacidad de cualquiera de las partes; b) el venc'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'contrato', 'articulo 1441'], segments: [], amendments: [] },
  { id: 'ccyc-art-1442', lawId: 'codigo-civil-comercial', number: '1442', order: 1442, title: "Normas aplicables", text: "Normas aplicables. Las disposiciones de este Capítulo se aplican a todo contrato de colaboración, de organización o participativo, con comunidad de fin, que no sea sociedad. A estos contratos no se les aplican las normas sobre la sociedad, no son, ni por medio de ellos se constituyen, personas jurídicas, sociedades ni sujetos de derecho. A las comuniones de derechos reales y a la indivisión hereditaria no se les aplican las disposiciones sobre contratos asociativos ni las de la sociedad.", plainLanguageExplanation: "Establece el régimen de normas aplicables. Las disposiciones de este Capítulo se aplican a todo contrato de colaboración, de organización o participativo, con comunidad de fin, que no sea sociedad.", practicalEffects: ['En la práctica, este artículo rige normas aplicables. Las disposiciones de este Capítulo se aplican a todo contrato de colaboración, de organización o participativo, con comunidad de fin, que no sea sociedad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'aplicables', 'articulo 1442'], segments: [], amendments: [] },
  { id: 'ccyc-art-1443', lawId: 'codigo-civil-comercial', number: '1443', order: 1443, title: "Nulidad", text: "Nulidad. Si las partes son más de dos la nulidad del contrato respecto de una de las partes no produce la nulidad entre las demás y el incumplimiento de una no excusa el de las otras, excepto que la prestación de aquella que ha incumplido o respecto de la cual el contrato es nulo sea necesaria para la realización del objeto del contrato.", plainLanguageExplanation: "Establece el régimen de nulidad. Si las partes son más de dos la nulidad del contrato respecto de una de las partes no produce la nulidad entre las demás y el incumplimiento de una no excusa el de las otras, excepto que la prestación de aquella que ha incumplido o respecto de la cual el contrato es nulo sea nece", practicalEffects: ['En la práctica, este artículo rige nulidad. Si las partes son más de dos la nulidad del contrato respecto de una de las partes no produce la nulidad entre las demás y el incumplimiento de una no'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidadarticulo 1443'], segments: [], amendments: [] },
  { id: 'ccyc-art-1444', lawId: 'codigo-civil-comercial', number: '1444', order: 1444, title: "Forma", text: "Forma. Los contratos a que se refiere este Capítulo no están sujetos a requisitos de forma.", plainLanguageExplanation: "Establece el régimen de forma. Los contratos a que se refiere este Capítulo no están sujetos a requisitos de forma.", practicalEffects: ['En la práctica, este artículo rige forma. Los contratos a que se refiere este Capítulo no están sujetos a requisitos de forma.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 1444'], segments: [], amendments: [] },
  { id: 'ccyc-art-1445', lawId: 'codigo-civil-comercial', number: '1445', order: 1445, title: "Actuación en nombre común o de las partes", text: "Actuación en nombre común o de las partes. Cuando una parte trate con un tercero en nombre de todas las partes o de la organización común establecida en el contrato asociativo, las otras partes no devienen acreedores o deudores respecto del tercero sino de conformidad con las disposiciones sobre representación, lo dispuesto en el contrato, o las normas de las Secciones siguientes de este Capítulo.", plainLanguageExplanation: "Establece el régimen de actuación en nombre común o de las partes. Cuando una parte trate con un tercero en nombre de todas las partes o de la organización común establecida en el contrato asociativo, las otras partes no devienen acreedores o deudores respecto del tercero sino de conformidad con las disposiciones sobre representación, lo dispues", practicalEffects: ['En la práctica, este artículo rige actuación en nombre común o de las partes. Cuando una parte trate con un tercero en nombre de todas las partes o de la organización común establecida en el contrato asociativo, las otras partes'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actuacin', 'nombre', 'comn', 'partes', 'articulo 1445'], segments: [], amendments: [] },
  { id: 'ccyc-art-1446', lawId: 'codigo-civil-comercial', number: '1446', order: 1446, title: "Libertad de contenidos", text: "Libertad de contenidos. Además de poder optar por los tipos que se regulan en las Secciones siguientes de este Capítulo, las partes tienen libertad para configurar estos contratos con otros contenidos.", plainLanguageExplanation: "Establece el régimen de libertad de contenidos. Además de poder optar por los tipos que se regulan en las Secciones siguientes de este Capítulo, las partes tienen libertad para configurar estos contratos con otros contenidos.", practicalEffects: ['En la práctica, este artículo rige libertad de contenidos. Además de poder optar por los tipos que se regulan en las Secciones siguientes de este Capítulo, las partes tienen libertad para configurar estos cont'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad', 'contenidos', 'articulo 1446'], segments: [], amendments: [] },
  { id: 'ccyc-art-1447', lawId: 'codigo-civil-comercial', number: '1447', order: 1447, title: "Efectos entre partes", text: "Efectos entre partes. Aunque la inscripción esté prevista en las Secciones siguientes de este Capítulo, los contratos no inscriptos producen efectos entre las partes. SECCION 2ª Negocio en participación", plainLanguageExplanation: "Establece el régimen de efectos entre partes. Aunque la inscripción esté prevista en las Secciones siguientes de este Capítulo, los contratos no inscriptos producen efectos entre las partes.", practicalEffects: ['En la práctica, este artículo rige efectos entre partes. Aunque la inscripción esté prevista en las Secciones siguientes de este Capítulo, los contratos no inscriptos producen efectos entre las partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'entre', 'partes', 'articulo 1447'], segments: [], amendments: [] },
  { id: 'ccyc-art-1448', lawId: 'codigo-civil-comercial', number: '1448', order: 1448, title: "Definición", text: "Definición. El negocio en participación tiene por objeto la realización de una o más operaciones determinadas a cumplirse mediante aportaciones comunes y a nombre personal del gestor. No tiene denominación, no está sometido a requisitos de forma, ni se inscribe en el Registro Público.", plainLanguageExplanation: "Establece el régimen de definición. El negocio en participación tiene por objeto la realización de una o más operaciones determinadas a cumplirse mediante aportaciones comunes y a nombre personal del gestor.", practicalEffects: ['En la práctica, este artículo rige definición. El negocio en participación tiene por objeto la realización de una o más operaciones determinadas a cumplirse mediante aportaciones comunes y a nombre personal del gestor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1448'], segments: [], amendments: [] },
  { id: 'ccyc-art-1449', lawId: 'codigo-civil-comercial', number: '1449', order: 1449, title: "Gestor", text: "Gestor. Actuación y responsabilidad. Los terceros adquieren derechos y asumen obligaciones sólo respecto del gestor. La responsabilidad de éste es ilimitada. Si actúa más de un gestor son solidariamente responsables.", plainLanguageExplanation: "Establece el régimen de gestor. Actuación y responsabilidad.", practicalEffects: ['En la práctica, este artículo rige gestor. Actuación y responsabilidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gestorarticulo 1449'], segments: [], amendments: [] },
  { id: 'ccyc-art-1450', lawId: 'codigo-civil-comercial', number: '1450', order: 1450, title: "Partícipe", text: "Partícipe. Partícipe es la parte del negocio que no actúa frente a los terceros. No tiene acción contra éstos ni éstos contra aquél, en tanto no se exteriorice la apariencia de una actuación común.", plainLanguageExplanation: "Establece el régimen de partícipe. Partícipe es la parte del negocio que no actúa frente a los terceros.", practicalEffects: ['En la práctica, este artículo rige partícipe. Partícipe es la parte del negocio que no actúa frente a los terceros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['partcipearticulo 1450'], segments: [], amendments: [] },
  { id: 'ccyc-art-1451', lawId: 'codigo-civil-comercial', number: '1451', order: 1451, title: "Derechos de información y rendición de cuentas", text: "Derechos de información y rendición de cuentas. El partícipe tiene derecho a que el gestor le brinde información y acceso a la documentación relativa al negocio. También tiene derecho a la rendición de cuentas de la gestión en la forma y en el tiempo pactados; y en defecto de pacto, anualmente y al concluir la negociación.", plainLanguageExplanation: "Establece el régimen de derechos de información y rendición de cuentas. El partícipe tiene derecho a que el gestor le brinde información y acceso a la documentación relativa al negocio.", practicalEffects: ['En la práctica, este artículo rige derechos de información y rendición de cuentas. El partícipe tiene derecho a que el gestor le brinde información y acceso a la documentación relativa al negocio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'informacin', 'rendicin', 'cuentas', 'articulo 1451'], segments: [], amendments: [] },
  { id: 'ccyc-art-1452', lawId: 'codigo-civil-comercial', number: '1452', order: 1452, title: "Limitación de las pérdidas", text: "Limitación de las pérdidas. Las pérdidas que afecten al partícipe no pueden superar el valor de su aporte. SECCION 3ª Agrupaciones de colaboración", plainLanguageExplanation: "Establece el régimen de limitación de las pérdidas. Las pérdidas que afecten al partícipe no pueden superar el valor de su aporte.", practicalEffects: ['En la práctica, este artículo rige limitación de las pérdidas. Las pérdidas que afecten al partícipe no pueden superar el valor de su aporte.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['limitacin', 'prdidas', 'articulo 1452'], segments: [], amendments: [] },
  { id: 'ccyc-art-1453', lawId: 'codigo-civil-comercial', number: '1453', order: 1453, title: "Definición", text: "Definición. Hay contrato de agrupación de colaboración cuando las partes establecen una organización común con la finalidad de facilitar o desarrollar determinadas fases de la actividad de sus miembros o de perfeccionar o incrementar el resultado de tales actividades.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de agrupación de colaboración cuando las partes establecen una organización común con la finalidad de facilitar o desarrollar determinadas fases de la actividad de sus miembros o de perfeccionar o incrementar el resultado de tales actividades.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de agrupación de colaboración cuando las partes establecen una organización común con la finalidad de facilitar o desarrollar determinada'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1453'], segments: [], amendments: [] },
  { id: 'ccyc-art-1454', lawId: 'codigo-civil-comercial', number: '1454', order: 1454, title: "Ausencia de finalidad lucrativa", text: "Ausencia de finalidad lucrativa. La agrupación, en cuanto tal, no puede perseguir fines de lucro. Las ventajas económicas que genere su actividad deben recaer directamente en el patrimonio de las partes agrupadas o consorciadas. La agrupación no puede ejercer funciones de dirección sobre la actividad de sus miembros.", plainLanguageExplanation: "Establece el régimen de ausencia de finalidad lucrativa. La agrupación, en cuanto tal, no puede perseguir fines de lucro.", practicalEffects: ['En la práctica, este artículo rige ausencia de finalidad lucrativa. La agrupación, en cuanto tal, no puede perseguir fines de lucro.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ausencia', 'finalidad', 'lucrativa', 'articulo 1454'], segments: [], amendments: [] },
  { id: 'ccyc-art-1455', lawId: 'codigo-civil-comercial', number: '1455', order: 1455, title: "Contrato", text: "Contrato. Forma y contenido. El contrato debe otorgarse por instrumento público o privado con firma certificada notarialmente e inscribirse en el Registro Público que corresponda. Una copia certificada con los datos de su correspondiente inscripción debe ser remitida por el Registro al organismo de aplicación del régimen de defensa de la competencia. El contrato debe contener: a) el objeto de la agrupación; b) la duración, que no puede exceder de diez años. Si se establece por más tiempo, queda reducida a dicho plazo. En caso de omisión del plazo, se entiende que la duración es de diez años. Puede ser prorrogada antes de su vencimiento por decisión unánime de los participantes por sucesivos plazos de hasta diez años. El contrato no puede prorrogarse si hubiese acreedores embargantes de los participantes y no se los desinteresa previamente; c) la denominación, que se forma con un nombre de fantasía integrado con la palabra 'agrupación'; d) el nombre, razón social o denominación, el domicilio y los datos de inscripción registral del contrato o estatuto o de la matriculación e individualización, en su caso, de cada uno de los participantes. En el caso de sociedades, la relación de la resolución del órgano social que aprueba la contratación de la agrupación, así como su fecha y número de acta; e) la constitución de un domicilio especial para todos los efectos que deriven del contrato de agrupación, tanto entre las partes como respecto de terceros; f) las obligaciones asumidas por los participantes, las contribuciones debidas al fondo común operativo y los modos de financiar las actividades comunes; g) la participación que cada contratante ha de tener en las actividades comunes y en sus resultados; h) los medios, atribuciones y poderes que se establecen para dirigir la organización y actividad común, administrar el fondo operativo, representar individual y colectivamente a los participantes y controlar su actividad al solo efecto de comprobar el cumplimiento de las obligaciones asumidas; i) los casos de separación y exclusión; j) los requisitos de admisión de nuevos participantes; k) las sanciones por incumplimiento de obligaciones; l) las normas para la confección de estados de situación, a cuyo efecto los administradores deben llevar, con las formalidades establecidas por este Código, los libros habilitados a nombre de la agrupación que requiera la naturaleza e importancia de la actividad común.", plainLanguageExplanation: "Establece el régimen de contrato. Forma y contenido.", practicalEffects: ['En la práctica, este artículo rige contrato. Forma y contenido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratoarticulo 1455'], segments: [], amendments: [] },
  { id: 'ccyc-art-1456', lawId: 'codigo-civil-comercial', number: '1456', order: 1456, title: "Resoluciones", text: "Resoluciones. Las resoluciones relativas a la realización del objeto de la agrupación se adoptan por el voto de la mayoría absoluta de los participantes, excepto disposición contraria del contrato. La impugnación de las resoluciones sólo puede fundarse en la violación de disposiciones legales o contractuales. La acción debe ser dirigida contra cada uno de los integrantes de la agrupación y plantearse ante el tribunal del domicilio fijado en el contrato, dentro de los treinta días de haberse notificado fehacientemente la decisión de la agrupación. Las reuniones o consultas a los participantes deben efectuarse cada vez que lo requiera un administrador o cualquiera de los participantes. No puede modificarse el contrato sin el consentimiento unánime de los participantes.", plainLanguageExplanation: "Establece el régimen de resoluciones. Las resoluciones relativas a la realización del objeto de la agrupación se adoptan por el voto de la mayoría absoluta de los participantes, excepto disposición contraria del contrato.", practicalEffects: ['En la práctica, este artículo rige resoluciones. Las resoluciones relativas a la realización del objeto de la agrupación se adoptan por el voto de la mayoría absoluta de los participantes, excepto disposición contraria del contrato.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resolucionesarticulo 1456'], segments: [], amendments: [] },
  { id: 'ccyc-art-1457', lawId: 'codigo-civil-comercial', number: '1457', order: 1457, title: "Dirección y administración", text: "Dirección y administración. La dirección y administración debe estar a cargo de una o más personas humanas designadas en el contrato, o posteriormente por resolución de los participantes. Son aplicables las reglas del mandato. En caso de ser varios los administradores, si nada se dice en el contrato pueden actuar indistintamente.", plainLanguageExplanation: "Establece el régimen de dirección y administración. La dirección y administración debe estar a cargo de una o más personas humanas designadas en el contrato, o posteriormente por resolución de los participantes.", practicalEffects: ['En la práctica, este artículo rige dirección y administración. La dirección y administración debe estar a cargo de una o más personas humanas designadas en el contrato, o posteriormente por resolución de los participantes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['direccin', 'administracin', 'articulo 1457'], segments: [], amendments: [] },
  { id: 'ccyc-art-1458', lawId: 'codigo-civil-comercial', number: '1458', order: 1458, title: "Fondo común operativo", text: "Fondo común operativo. Las contribuciones de los participantes y los bienes que con ellas se adquieran, constituyen el fondo común operativo de la agrupación. Durante el plazo establecido para su duración, los bienes se deben mantener indivisos, y los acreedores particulares de los participantes no pueden hacer valer su derecho sobre ellos.", plainLanguageExplanation: "Establece el régimen de fondo común operativo. Las contribuciones de los participantes y los bienes que con ellas se adquieran, constituyen el fondo común operativo de la agrupación.", practicalEffects: ['En la práctica, este artículo rige fondo común operativo. Las contribuciones de los participantes y los bienes que con ellas se adquieran, constituyen el fondo común operativo de la agrupación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fondo', 'comn', 'operativo', 'articulo 1458'], segments: [], amendments: [] },
  { id: 'ccyc-art-1459', lawId: 'codigo-civil-comercial', number: '1459', order: 1459, title: "Obligaciones", text: "Obligaciones. Solidaridad. Los participantes responden ilimitada y solidariamente respecto de terceros por las obligaciones que sus representantes asuman en nombre de la agrupación. La acción queda expedita después de haberse interpelado infructuosamente al administrador de la agrupación. El demandado por cumplimiento de la obligación tiene derecho a oponer las defensas personales y las comunes que correspondan a la agrupación. El participante representado responde solidariamente con el fondo común operativo por las obligaciones que los representantes hayan asumido en representación de un participante, haciéndolo saber al tercero al tiempo de obligarse.", plainLanguageExplanation: "Establece el régimen de obligaciones. Solidaridad.", practicalEffects: ['En la práctica, este artículo rige obligaciones. Solidaridad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacionesarticulo 1459'], segments: [], amendments: [] },
  { id: 'ccyc-art-1460', lawId: 'codigo-civil-comercial', number: '1460', order: 1460, title: "Estados de situación", text: "Estados de situación. Los estados de situación de la agrupación deben ser sometidos a decisión de los participantes dentro de los noventa días del cierre de cada ejercicio anual. Los beneficios o pérdidas o, en su caso, los ingresos y gastos de los participantes derivados de su actividad, pueden ser imputados al ejercicio en que se producen o a aquel en el que se aprueban las cuentas de la agrupación.", plainLanguageExplanation: "Establece el régimen de estados de situación. Los estados de situación de la agrupación deben ser sometidos a decisión de los participantes dentro de los noventa días del cierre de cada ejercicio anual.", practicalEffects: ['En la práctica, este artículo rige estados de situación. Los estados de situación de la agrupación deben ser sometidos a decisión de los participantes dentro de los noventa días del cierre de cada ejercicio anual.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['estados', 'situacin', 'articulo 1460'], segments: [], amendments: [] },
  { id: 'ccyc-art-1461', lawId: 'codigo-civil-comercial', number: '1461', order: 1461, title: "Extinción", text: "Extinción. El contrato de agrupación se extingue: a) por la decisión de los participantes; b) por expiración del plazo por el cual se constituye; por la consecución del objeto para el que se forma o por la imposibilidad sobreviniente de lograrlo; c) por reducción a uno del número de participantes; d) por incapacidad, muerte, disolución o quiebra de un participante, a menos que el contrato prevea su continuación o que los demás participantes lo decidan por unanimidad; e) por decisión firme de la autoridad competente que considere que la agrupación, por su objeto o por su actividad, persigue la realización de prácticas restrictivas de la competencia; f) por causas específicamente previstas en el contrato.", plainLanguageExplanation: "Establece el régimen de extinción. El contrato de agrupación se extingue: a) por la decisión de los participantes; b) por expiración del plazo por el cual se constituye; por la consecución del objeto para el que se forma o por la imposibilidad sobreviniente de lograrlo; c) por reducción a uno del número de partici", practicalEffects: ['En la práctica, este artículo rige extinción. El contrato de agrupación se extingue: a) por la decisión de los participantes; b) por expiración del plazo por el cual se constituye; por la consecuc'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincinarticulo 1461'], segments: [], amendments: [] },
  { id: 'ccyc-art-1462', lawId: 'codigo-civil-comercial', number: '1462', order: 1462, title: "Resolución parcial no voluntaria de vínculo", text: "Resolución parcial no voluntaria de vínculo. Sin perjuicio de lo establecido en el contrato, cualquier participante puede ser excluido por decisión unánime de los demás, si contraviene habitualmente sus obligaciones, perturba el funcionamiento de la agrupación o incurre en un incumplimiento grave. Cuando el contrato sólo vincula a dos personas, si una incurre en alguna de las causales indicadas, el otro participante puede declarar la resolución del contrato y reclamar del incumplidor el resarcimiento de los daños. SECCION 4ª Uniones Transitorias", plainLanguageExplanation: "Establece el régimen de resolución parcial no voluntaria de vínculo. Sin perjuicio de lo establecido en el contrato, cualquier participante puede ser excluido por decisión unánime de los demás, si contraviene habitualmente sus obligaciones, perturba el funcionamiento de la agrupación o incurre en un incumplimiento grave.", practicalEffects: ['En la práctica, este artículo rige resolución parcial no voluntaria de vínculo. Sin perjuicio de lo establecido en el contrato, cualquier participante puede ser excluido por decisión unánime de los demás, si contraviene habitualme'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resolucin', 'parcial', 'voluntaria', 'vnculo', 'articulo 1462'], segments: [], amendments: [] },
  { id: 'ccyc-art-1463', lawId: 'codigo-civil-comercial', number: '1463', order: 1463, title: "Definición", text: "Definición. Hay contrato de unión transitoria cuando las partes se reúnen para el desarrollo o ejecución de obras, servicios o suministros concretos, dentro o fuera de la República. Pueden desarrollar o ejecutar las obras y servicios complementarios y accesorios al objeto principal.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de unión transitoria cuando las partes se reúnen para el desarrollo o ejecución de obras, servicios o suministros concretos, dentro o fuera de la República.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de unión transitoria cuando las partes se reúnen para el desarrollo o ejecución de obras, servicios o suministros concretos, dentro o fuera de la República.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1463'], segments: [], amendments: [] },
  { id: 'ccyc-art-1464', lawId: 'codigo-civil-comercial', number: '1464', order: 1464, title: "Contrato", text: "Contrato. Forma y contenido. El contrato se debe otorgar por instrumento público o privado con firma certificada notarialmente, que debe contener: a) el objeto, con determinación concreta de las actividades y los medios para su realización; b) la duración, que debe ser igual a la de la obra, servicio o suministro que constituye el objeto; c) la denominación, que debe ser la de alguno, algunos o todos los miembros, seguida de la expresión 'unión transitoria'; d) el nombre, razón social o denominación, el domicilio y, si los tiene, los datos de la inscripción registral del contrato o estatuto o de la matriculación o individualización que corresponde a cada uno de los miembros. En el caso de sociedades, la relación de la resolución del órgano social que aprueba la celebración de la unión transitoria, su fecha y número de acta; e) la constitución de un domicilio especial para todos los efectos que deriven del contrato, tanto entre partes como respecto de terceros; f) las obligaciones asumidas, las contribuciones debidas al fondo común operativo y los modos de financiar las actividades comunes en su caso; g) el nombre y el domicilio del representante, que puede ser persona humana o jurídica; h) el método para determinar la participación de las partes en la distribución de los ingresos y la asunción de los gastos de la unión o, en su caso, de los resultados; i) los supuestos de separación y exclusión de los miembros y las causales de extinción del contrato; j) los requisitos de admisión de nuevos miembros; k) las sanciones por incumplimiento de obligaciones; l) las normas para la elaboración de los estados de situación, a cuyo efecto los administradores deben llevar, con las formalidades establecidas en los artículos 320 y siguientes, los libros exigibles y habilitados a nombre de la unión transitoria que requieran la naturaleza e importancia de la actividad común.", plainLanguageExplanation: "Establece el régimen de contrato. Forma y contenido.", practicalEffects: ['En la práctica, este artículo rige contrato. Forma y contenido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratoarticulo 1464'], segments: [], amendments: [] },
  { id: 'ccyc-art-1465', lawId: 'codigo-civil-comercial', number: '1465', order: 1465, title: "Representante", text: "Representante. El representante tiene los poderes suficientes de todos y cada uno de los miembros para ejercer los derechos y contraer las obligaciones que hacen al desarrollo o ejecución de la obra, servicio o suministro; la designación del representante no es revocable sin causa, excepto decisión unánime de los participantes. Mediando justa causa, la revocación puede ser decidida por el voto de la mayoría absoluta.", plainLanguageExplanation: "Establece el régimen de representante. El representante tiene los poderes suficientes de todos y cada uno de los miembros para ejercer los derechos y contraer las obligaciones que hacen al desarrollo o ejecución de la obra, servicio o suministro; la designación del representante no es revocable sin causa, excepto deci", practicalEffects: ['En la práctica, este artículo rige representante. El representante tiene los poderes suficientes de todos y cada uno de los miembros para ejercer los derechos y contraer las obligaciones que hacen al'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representantearticulo 1465'], segments: [], amendments: [] },
  { id: 'ccyc-art-1466', lawId: 'codigo-civil-comercial', number: '1466', order: 1466, title: "Inscripción registral", text: "Inscripción registral. El contrato y la designación del representante deben ser inscriptos en el Registro Público que corresponda.", plainLanguageExplanation: "Establece el régimen de inscripción registral. El contrato y la designación del representante deben ser inscriptos en el Registro Público que corresponda.", practicalEffects: ['En la práctica, este artículo rige inscripción registral. El contrato y la designación del representante deben ser inscriptos en el Registro Público que corresponda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inscripcin', 'registral', 'articulo 1466'], segments: [], amendments: [] },
  { id: 'ccyc-art-1467', lawId: 'codigo-civil-comercial', number: '1467', order: 1467, title: "Obligaciones", text: "Obligaciones. No solidaridad. Excepto disposición en contrario del contrato, no se presume la solidaridad de los miembros por los actos y operaciones que realicen en la unión transitoria, ni por las obligaciones contraídas frente a los terceros.", plainLanguageExplanation: "Establece el régimen de obligaciones. No solidaridad.", practicalEffects: ['En la práctica, este artículo rige obligaciones. No solidaridad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacionesarticulo 1467'], segments: [], amendments: [] },
  { id: 'ccyc-art-1468', lawId: 'codigo-civil-comercial', number: '1468', order: 1468, title: "Acuerdos", text: "Acuerdos. Los acuerdos se deben adoptar siempre por unanimidad, excepto pacto en contrario.", plainLanguageExplanation: "Establece el régimen de acuerdos. Los acuerdos se deben adoptar siempre por unanimidad, excepto pacto en contrario.", practicalEffects: ['En la práctica, este artículo rige acuerdos. Los acuerdos se deben adoptar siempre por unanimidad, excepto pacto en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acuerdosarticulo 1468'], segments: [], amendments: [] },
  { id: 'ccyc-art-1469', lawId: 'codigo-civil-comercial', number: '1469', order: 1469, title: "Quiebra, muerte o incapacidad", text: "Quiebra, muerte o incapacidad. La quiebra de cualquiera de los participantes, y la muerte o incapacidad de las personas humanas integrantes no produce la extinción del contrato de unión transitoria, el que continúa con los restantes si acuerdan la manera de hacerse cargo de las prestaciones ante los terceros. SECCION 5ª Consorcios de cooperación", plainLanguageExplanation: "Establece el régimen de quiebra, muerte o incapacidad. La quiebra de cualquiera de los participantes, y la muerte o incapacidad de las personas humanas integrantes no produce la extinción del contrato de unión transitoria, el que continúa con los restantes si acuerdan la manera de hacerse cargo de las prestaciones ante los terceros.", practicalEffects: ['En la práctica, este artículo rige quiebra, muerte o incapacidad. La quiebra de cualquiera de los participantes, y la muerte o incapacidad de las personas humanas integrantes no produce la extinción del contrato de u'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['quiebra', 'muerte', 'incapacidad', 'articulo 1469'], segments: [], amendments: [] },
  { id: 'ccyc-art-1470', lawId: 'codigo-civil-comercial', number: '1470', order: 1470, title: "Definición", text: "Definición. Hay contrato de consorcio de cooperación cuando las partes establecen una organización común para facilitar, desarrollar, incrementar o concretar operaciones relacionadas con la actividad económica de sus miembros a fin de mejorar o acrecentar sus resultados.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de consorcio de cooperación cuando las partes establecen una organización común para facilitar, desarrollar, incrementar o concretar operaciones relacionadas con la actividad económica de sus miembros a fin de mejorar o acrecentar sus resultados.", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de consorcio de cooperación cuando las partes establecen una organización común para facilitar, desarrollar, incrementar o concretar oper'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1470'], segments: [], amendments: [] },
  { id: 'ccyc-art-1471', lawId: 'codigo-civil-comercial', number: '1471', order: 1471, title: "Exclusión de función de dirección o control", text: "Exclusión de función de dirección o control. El consorcio de cooperación no puede ejercer funciones de dirección o control sobre la actividad de sus miembros.", plainLanguageExplanation: "Establece el régimen de exclusión de función de dirección o control. El consorcio de cooperación no puede ejercer funciones de dirección o control sobre la actividad de sus miembros.", practicalEffects: ['En la práctica, este artículo rige exclusión de función de dirección o control. El consorcio de cooperación no puede ejercer funciones de dirección o control sobre la actividad de sus miembros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exclusin', 'funcin', 'direccin', 'control', 'articulo 1471'], segments: [], amendments: [] },
  { id: 'ccyc-art-1472', lawId: 'codigo-civil-comercial', number: '1472', order: 1472, title: "Participación en los resultados", text: "Participación en los resultados. Los resultados que genera la actividad desarrollada por el consorcio de cooperación se distribuyen entre sus miembros en la proporción que fija el contrato y, en su defecto, por partes iguales.", plainLanguageExplanation: "Establece el régimen de participación en los resultados. Los resultados que genera la actividad desarrollada por el consorcio de cooperación se distribuyen entre sus miembros en la proporción que fija el contrato y, en su defecto, por partes iguales.", practicalEffects: ['En la práctica, este artículo rige participación en los resultados. Los resultados que genera la actividad desarrollada por el consorcio de cooperación se distribuyen entre sus miembros en la proporción que fija el con'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['participacin', 'resultados', 'articulo 1472'], segments: [], amendments: [] },
  { id: 'ccyc-art-1473', lawId: 'codigo-civil-comercial', number: '1473', order: 1473, title: "Forma", text: "Forma. El contrato debe otorgarse por instrumento público o privado con firma certificada notarialmente, e inscribirse conjuntamente con la designación de sus representantes en el Registro Público que corresponda", plainLanguageExplanation: "Establece el régimen de forma. El contrato debe otorgarse por instrumento público o privado con firma certificada notarialmente, e inscribirse conjuntamente con la designación de sus representantes en el Registro Público que corresponda", practicalEffects: ['En la práctica, este artículo rige forma. El contrato debe otorgarse por instrumento público o privado con firma certificada notarialmente, e inscribirse conjuntamente con la designación de su'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 1473'], segments: [], amendments: [] },
  { id: 'ccyc-art-1474', lawId: 'codigo-civil-comercial', number: '1474', order: 1474, title: "Contenido", text: "Contenido. El contrato debe contener: a) el nombre y datos personales de los miembros individuales, y en el caso de personas jurídicas, el nombre, denominación, domicilio y, si los tiene, datos de inscripción del contrato o estatuto social de cada uno de los participantes. Las personas jurídicas, además, deben consignar la fecha del acta y, la mención del órgano social que aprueba la participación en el consorcio; b) el objeto del consorcio; c) el plazo de duración del contrato; d) la denominación, que se forma con un nombre de fantasía integrado con la leyenda 'Consorcio de cooperación'; e) la constitución de un domicilio especial para todos los efectos que deriven del contrato, tanto respecto de las partes como con relación a terceros; f) la constitución del fondo común operativo y la determinación de su monto, así como la participación que cada parte asume en el mismo, incluyéndose la forma de su actualización o aumento en su caso; g) las obligaciones y derechos que pactan los integrantes; h) la participación de cada contratante en la inversión del o de los proyectos del consorcio, si existen, y la proporción en que cada uno participa de los resultados; i) la proporción en que los participantes se responsabilizan por las obligaciones que asumen los representantes en su nombre; j) las formas y ámbitos de adopción de decisiones para el cumplimiento del objeto. Debe preverse la obligatoriedad de celebrar reunión para tratar los temas relacionados con los negocios propios del objeto cuando así lo solicita cualquiera de los participantes por sí o por representante. Las resoluciones se adoptan por mayoría absoluta de las partes, excepto que el contrato de constitución disponga otra forma de cómputo; k) la determinación del número de representantes del consorcio, nombre, domicilio y demás datos personales, forma de elección y de sustitución, así como sus facultades, poderes y, en caso de que la representación sea plural, formas de actuación. En caso de renuncia, incapacidad o revocación de mandato, el nuevo representante se designa por mayoría absoluta de los miembros, excepto disposición en contrario del contrato. Igual mecanismo se debe requerir para autorizar la sustitución de poder; l) las mayorías necesarias para la modificación del contrato constitutivo. En caso de silencio, se requiere unanimidad; m) las formas de tratamiento y las mayorías para decidir la exclusión y la admisión de nuevos participantes. En caso de silencio, la admisión de nuevos miembros requiere unanimidad; n) las sanciones por incumplimientos de los miembros y representantes; ñ) las causales de extinción del contrato y las formas de liquidación del consorcio; o) una fecha anual para el tratamiento del estado de situación patrimonial por los miembros del consorcio; p) la constitución del fondo operativo, el cual debe permanecer indiviso por todo el plazo de duración del consorcio.", plainLanguageExplanation: "Establece el régimen de contenido. El contrato debe contener: a) el nombre y datos personales de los miembros individuales, y en el caso de personas jurídicas, el nombre, denominación, domicilio y, si los tiene, datos de inscripción del contrato o estatuto social de cada uno de los participantes.", practicalEffects: ['En la práctica, este artículo rige contenido. El contrato debe contener: a) el nombre y datos personales de los miembros individuales, y en el caso de personas jurídicas, el nombre, denominación,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contenidoarticulo 1474'], segments: [], amendments: [] },
  { id: 'ccyc-art-1475', lawId: 'codigo-civil-comercial', number: '1475', order: 1475, title: "Reglas contables", text: "Reglas contables. El contrato debe establecer las reglas sobre confección y aprobación de los estados de situación patrimonial, atribución de resultados y rendición de cuentas, que reflejen adecuadamente todas., las operaciones llevadas a cabo en el ejercicio mediante el empleo de técnicas contables adecuadas. Los movimientos deben consignarse en libros contables llevados con las formalidades establecidas en las leyes. Se debe llevar un libro de actas en el cual se deben labrar las correspondientes a todas las reuniones que se realizan y a las resoluciones que se adoptan.", plainLanguageExplanation: "Establece el régimen de reglas contables. El contrato debe establecer las reglas sobre confección y aprobación de los estados de situación patrimonial, atribución de resultados y rendición de cuentas, que reflejen adecuadamente todas., las operaciones llevadas a cabo en el ejercicio mediante el empleo de técnicas contables adecuadas.", practicalEffects: ['En la práctica, este artículo rige reglas contables. El contrato debe establecer las reglas sobre confección y aprobación de los estados de situación patrimonial, atribución de resultados y rendición de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'contables', 'articulo 1475'], segments: [], amendments: [] },
  { id: 'ccyc-art-1476', lawId: 'codigo-civil-comercial', number: '1476', order: 1476, title: "Obligaciones y responsabilidad del representante", text: "Obligaciones y responsabilidad del representante. El representante debe llevar los libros de contabilidad y confeccionar los estados de situación patrimonial. También debe informar a los miembros sobre la existencia de causales de extinción previstas en el contrato o en la ley y tomar las medidas y recaudos urgentes que correspondan. Es responsable de que en toda actuación sea exteriorizado el carácter de consorcio.", plainLanguageExplanation: "Establece el régimen de obligaciones y responsabilidad del representante. El representante debe llevar los libros de contabilidad y confeccionar los estados de situación patrimonial.", practicalEffects: ['En la práctica, este artículo rige obligaciones y responsabilidad del representante. El representante debe llevar los libros de contabilidad y confeccionar los estados de situación patrimonial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'responsabilidad', 'representante', 'articulo 1476'], segments: [], amendments: [] },
  { id: 'ccyc-art-1477', lawId: 'codigo-civil-comercial', number: '1477', order: 1477, title: "Responsabilidad de los participantes", text: "Responsabilidad de los participantes. El contrato puede establecer la proporción en que cada miembro responde por las obligaciones asumidas en nombre del consorcio. En caso de silencio todos los miembros son solidariamente responsables.", plainLanguageExplanation: "Establece el régimen de responsabilidad de los participantes. El contrato puede establecer la proporción en que cada miembro responde por las obligaciones asumidas en nombre del consorcio.", practicalEffects: ['En la práctica, este artículo rige responsabilidad de los participantes. El contrato puede establecer la proporción en que cada miembro responde por las obligaciones asumidas en nombre del consorcio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'participantes', 'articulo 1477'], segments: [], amendments: [] },
  { id: 'ccyc-art-1478', lawId: 'codigo-civil-comercial', number: '1478', order: 1478, title: "Extinción del contrato", text: "Extinción del contrato. El contrato de consorcio de cooperación se extingue por: a) el agotamiento de su objeto o la imposibilidad de ejecutarlo; b) la expiración del plazo establecido; c) la decisión unánime de sus miembros; d) la reducción a uno del número de miembros. La muerte, incapacidad, disolución, liquidación, concurso preventivo, cesación de pagos o quiebra de alguno de los miembros del consorcio, no extingue el contrato, que continúa con los restantes, excepto que ello resulte imposible fáctica o jurídicamente. CAPITULO 17 Agencia", plainLanguageExplanation: "Establece el régimen de extinción del contrato. El contrato de consorcio de cooperación se extingue por: a) el agotamiento de su objeto o la imposibilidad de ejecutarlo; b) la expiración del plazo establecido; c) la decisión unánime de sus miembros; d) la reducción a uno del número de miembros.", practicalEffects: ['En la práctica, este artículo rige extinción del contrato. El contrato de consorcio de cooperación se extingue por: a) el agotamiento de su objeto o la imposibilidad de ejecutarlo; b) la expiración del plazo e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'contrato', 'articulo 1478'], segments: [], amendments: [] },
  { id: 'ccyc-art-1479', lawId: 'codigo-civil-comercial', number: '1479', order: 1479, title: "Definición y forma", text: "Definición y forma. Hay contrato de agencia cuando una parte, denominada agente, se obliga a promover negocios por cuenta de otra denominada preponente o empresario, de manera estable, continuada e independiente, sin que medie relación laboral alguna, mediante una retribución. El agente es un intermediario independiente, no asume el riesgo de las operaciones ni representa al preponente. El contrato debe instrumentarse por escrito.", plainLanguageExplanation: "Establece el régimen de definición y forma. Hay contrato de agencia cuando una parte, denominada agente, se obliga a promover negocios por cuenta de otra denominada preponente o empresario, de manera estable, continuada e independiente, sin que medie relación laboral alguna, mediante una retribución.", practicalEffects: ['En la práctica, este artículo rige definición y forma. Hay contrato de agencia cuando una parte, denominada agente, se obliga a promover negocios por cuenta de otra denominada preponente o empresario, de m'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicin', 'forma', 'articulo 1479'], segments: [], amendments: [] },
  { id: 'ccyc-art-1480', lawId: 'codigo-civil-comercial', number: '1480', order: 1480, title: "Exclusividad", text: "Exclusividad. El agente tiene derecho a la exclusividad en el ramo de los negocios, en la zona geográfica, o respecto del grupo de personas, expresamente determinados en el contrato.", plainLanguageExplanation: "Establece el régimen de exclusividad. El agente tiene derecho a la exclusividad en el ramo de los negocios, en la zona geográfica, o respecto del grupo de personas, expresamente determinados en el contrato.", practicalEffects: ['En la práctica, este artículo rige exclusividad. El agente tiene derecho a la exclusividad en el ramo de los negocios, en la zona geográfica, o respecto del grupo de personas, expresamente determinad'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exclusividadarticulo 1480'], segments: [], amendments: [] },
  { id: 'ccyc-art-1481', lawId: 'codigo-civil-comercial', number: '1481', order: 1481, title: "Relación con varios empresarios", text: "Relación con varios empresarios. El agente puede contratar sus servicios con varios empresarios. Sin embargo, no puede aceptar operaciones del mismo ramo de negocios o en competencia con las de uno de sus proponentes, sin que éste lo autorice expresamente.", plainLanguageExplanation: "Establece el régimen de relación con varios empresarios. El agente puede contratar sus servicios con varios empresarios.", practicalEffects: ['En la práctica, este artículo rige relación con varios empresarios. El agente puede contratar sus servicios con varios empresarios.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['relacin', 'varios', 'empresarios', 'articulo 1481'], segments: [], amendments: [] },
  { id: 'ccyc-art-1482', lawId: 'codigo-civil-comercial', number: '1482', order: 1482, title: "Garantía del agente", text: "Garantía del agente. El agente no puede constituirse en garante de la cobranza del comprador presentado al empresario, sino hasta el importe de la comisión que se le puede haber adelantado o cobrado, en virtud de la operación concluida por el principal.", plainLanguageExplanation: "Establece el régimen de garantía del agente. El agente no puede constituirse en garante de la cobranza del comprador presentado al empresario, sino hasta el importe de la comisión que se le puede haber adelantado o cobrado, en virtud de la operación concluida por el principal.", practicalEffects: ['En la práctica, este artículo rige garantía del agente. El agente no puede constituirse en garante de la cobranza del comprador presentado al empresario, sino hasta el importe de la comisión que se le puede'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garanta', 'agente', 'articulo 1482'], segments: [], amendments: [] },
  { id: 'ccyc-art-1483', lawId: 'codigo-civil-comercial', number: '1483', order: 1483, title: "Obligaciones del agente", text: "Obligaciones del agente. Son obligaciones del agente: a) velar por los intereses del empresario y actuar de buena fe en el ejercicio de sus actividades; b) ocuparse con la diligencia de un buen hombre de negocios de la promoción y, en su caso, de la conclusión de los actos u operaciones que le encomendaron; c) cumplir su cometido de conformidad con las instrucciones recibidas del empresario y transmitir a éste toda la información de la que disponga relativa a su gestión; d) informar al empresario, sin retraso, de todos los negocios tratados o concluidos y, en particular, lo relativo a la solvencia de los terceros con los que se proponen o se concluyen operaciones; e) recibir en nombre del empresario las reclamaciones de terceros sobre defectos o vicios de calidad o cantidad de los bienes vendidos o de los servicios prestados como consecuencia de las operaciones promovidas, aunque él no las haya concluido, y transmitírselas de inmediato; f) asentar en su contabilidad en forma independiente los actos u operaciones relativos a cada empresario por cuya cuenta actúe.", plainLanguageExplanation: "Establece el régimen de obligaciones del agente. Son obligaciones del agente: a) velar por los intereses del empresario y actuar de buena fe en el ejercicio de sus actividades; b) ocuparse con la diligencia de un buen hombre de negocios de la promoción y, en su caso, de la conclusión de los actos u operaciones que le encomendar", practicalEffects: ['En la práctica, este artículo rige obligaciones del agente. Son obligaciones del agente: a) velar por los intereses del empresario y actuar de buena fe en el ejercicio de sus actividades; b) ocuparse con la dil'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'agente', 'articulo 1483'], segments: [], amendments: [] },
  { id: 'ccyc-art-1484', lawId: 'codigo-civil-comercial', number: '1484', order: 1484, title: "Obligaciones del empresario", text: "Obligaciones del empresario. Son obligaciones del empresario: a) actuar de buena, fe, y hacer todo aquello que le incumbe, teniendo en cuenta las circunstancias del caso, para permitir al agente el ejercicio normal de su actividad; b) poner a disposición del agente con suficiente antelación y en la cantidad apropiada, muestras, catálogos, tarifas y demás elementos de que se disponga y sean necesarios para el desarrollo de las actividades del agente; c) pagar la remuneración pactada; d) comunicar al agente, dentro del plazo de uso o, en su defecto, dentro de los quince días hábiles de su conocimiento, la aceptación o rechazo de la propuesta que le haya sido transmitida; e) comunicar al agente, dentro del plazo de uso o, en su defecto, dentro de los quince días hábiles de la recepción de la orden, la ejecución parcial o la falta de ejecución del negocio propuesto.", plainLanguageExplanation: "Establece el régimen de obligaciones del empresario. Son obligaciones del empresario: a) actuar de buena, fe, y hacer todo aquello que le incumbe, teniendo en cuenta las circunstancias del caso, para permitir al agente el ejercicio normal de su actividad; b) poner a disposición del agente con suficiente antelación y en la cantidad", practicalEffects: ['En la práctica, este artículo rige obligaciones del empresario. Son obligaciones del empresario: a) actuar de buena, fe, y hacer todo aquello que le incumbe, teniendo en cuenta las circunstancias del caso, para per'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'empresario', 'articulo 1484'], segments: [], amendments: [] },
  { id: 'ccyc-art-1485', lawId: 'codigo-civil-comercial', number: '1485', order: 1485, title: "Representación del agente", text: "Representación del agente. El agente no representa al empresario a los fines de la conclusión y ejecución de los contratos en los que actúa, excepto para recibir las reclamaciones de terceros previstas en el artículo 1483, inciso e). El agente debe tener poder especial para cobrar los créditos resultantes de su gestión, pero en ningún caso puede conceder quitas o esperas ni consentir acuerdos, desistimientos o avenimientos concursales, sin facultades expresas, de carácter especial, en las que conste en forma específica el monto de la quita o el plazo de la espera. Se prohíbe al agente desistir de la cobranza de un crédito del empresario en forma total o parcial.", plainLanguageExplanation: "Establece el régimen de representación del agente. El agente no representa al empresario a los fines de la conclusión y ejecución de los contratos en los que actúa, excepto para recibir las reclamaciones de terceros previstas en el artículo 1483, inciso e).", practicalEffects: ['En la práctica, este artículo rige representación del agente. El agente no representa al empresario a los fines de la conclusión y ejecución de los contratos en los que actúa, excepto para recibir las reclamacion'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representacin', 'agente', 'articulo 1485'], segments: [], amendments: [] },
  { id: 'ccyc-art-1486', lawId: 'codigo-civil-comercial', number: '1486', order: 1486, title: "Remuneración", text: "Remuneración. Si no hay un pacto expreso, la remuneración del agente es una comisión variable según el volumen o el valor de los actos o contratos promovidos y, en su caso, concluidos por el agente, conforme con los usos y prácticas del lugar de actuación del agente.", plainLanguageExplanation: "Establece el régimen de remuneración. Si no hay un pacto expreso, la remuneración del agente es una comisión variable según el volumen o el valor de los actos o contratos promovidos y, en su caso, concluidos por el agente, conforme con los usos y prácticas del lugar de actuación del agente.", practicalEffects: ['En la práctica, este artículo rige remuneración. Si no hay un pacto expreso, la remuneración del agente es una comisión variable según el volumen o el valor de los actos o contratos promovidos y, en'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneracinarticulo 1486'], segments: [], amendments: [] },
  { id: 'ccyc-art-1487', lawId: 'codigo-civil-comercial', number: '1487', order: 1487, title: "Base para el cálculo", text: "Base para el cálculo. Cualquiera sea la forma de la retribución pactada, el agente tiene derecho a percibirla por las operaciones concluidas con su intervención, durante la vigencia del contrato de agencia y siempre que el precio sea cobrado por el empresario. En las mismas condiciones también tiene derecho: a) si existen operaciones concluidas con posterioridad a la finalización del contrato de agencia; b) si el contrato se concluye con un cliente que el agente presentara anteriormente para un negocio análogo, siempre que no haya otro agente con derecho a remuneración; c) si el agente tiene exclusividad para una zona geográfica o para un grupo determinado de personas, cuando el contrato se concluye con una persona perteneciente a dicha zona o grupo, aunque el agente no lo promueva, excepto pacto especial y expreso en contrario.", plainLanguageExplanation: "Establece el régimen de base para el cálculo. Cualquiera sea la forma de la retribución pactada, el agente tiene derecho a percibirla por las operaciones concluidas con su intervención, durante la vigencia del contrato de agencia y siempre que el precio sea cobrado por el empresario.", practicalEffects: ['En la práctica, este artículo rige base para el cálculo. Cualquiera sea la forma de la retribución pactada, el agente tiene derecho a percibirla por las operaciones concluidas con su intervención, durante la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['base', 'para', 'clculo', 'articulo 1487'], segments: [], amendments: [] },
  { id: 'ccyc-art-1488', lawId: 'codigo-civil-comercial', number: '1488', order: 1488, title: "Devengamiento de la comisión", text: "Devengamiento de la comisión. El derecho a la comisión surge al momento de la conclusión del contrato con el tercero y del pago del precio al empresario. La comisión debe ser liquidada al agente dentro de los veinte días hábiles contados a partir del pago total o parcial del precio al empresario. Cuando la actuación del agente se limita a la promoción del contrato, la orden transmitida al empresario se presume aceptada, a los fines del derecho a percibir en el futuro la remuneración, excepto rechazo o reserva formulada por éste en el término previsto en el artículo 1484, inciso d).", plainLanguageExplanation: "Establece el régimen de devengamiento de la comisión. El derecho a la comisión surge al momento de la conclusión del contrato con el tercero y del pago del precio al empresario.", practicalEffects: ['En la práctica, este artículo rige devengamiento de la comisión. El derecho a la comisión surge al momento de la conclusión del contrato con el tercero y del pago del precio al empresario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['devengamiento', 'comisin', 'articulo 1488'], segments: [], amendments: [] },
  { id: 'ccyc-art-1489', lawId: 'codigo-civil-comercial', number: '1489', order: 1489, title: "Remuneración sujeta a ejecución del contrato", text: "Remuneración sujeta a ejecución del contrato. La cláusula que subordina la percepción de la remuneración, en todo o en parte, a la ejecución del contrato, es válida si ha sido expresamente pactada.", plainLanguageExplanation: "Establece el régimen de remuneración sujeta a ejecución del contrato. La cláusula que subordina la percepción de la remuneración, en todo o en parte, a la ejecución del contrato, es válida si ha sido expresamente pactada.", practicalEffects: ['En la práctica, este artículo rige remuneración sujeta a ejecución del contrato. La cláusula que subordina la percepción de la remuneración, en todo o en parte, a la ejecución del contrato, es válida si ha sido expresamente pactada'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneracin', 'sujeta', 'ejecucin', 'contrato', 'articulo 1489'], segments: [], amendments: [] },
  { id: 'ccyc-art-1490', lawId: 'codigo-civil-comercial', number: '1490', order: 1490, title: "Gastos", text: "Gastos. Excepto pacto en contrario, el agente no tiene derecho al reembolso de gastos que le origine el ejercicio de su actividad.", plainLanguageExplanation: "Establece el régimen de gastos. Excepto pacto en contrario, el agente no tiene derecho al reembolso de gastos que le origine el ejercicio de su actividad.", practicalEffects: ['En la práctica, este artículo rige gastos. Excepto pacto en contrario, el agente no tiene derecho al reembolso de gastos que le origine el ejercicio de su actividad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gastosarticulo 1490'], segments: [], amendments: [] },
  { id: 'ccyc-art-1491', lawId: 'codigo-civil-comercial', number: '1491', order: 1491, title: "Plazo", text: "Plazo. Excepto pacto en contrario, se entiende que el contrato de agencia se celebra por tiempo indeterminado. La continuación de la relación con posterioridad al vencimiento de un contrato de agencia con plazo determinado, lo transforma en contrato por tiempo indeterminado.", plainLanguageExplanation: "Establece el régimen de plazo. Excepto pacto en contrario, se entiende que el contrato de agencia se celebra por tiempo indeterminado.", practicalEffects: ['En la práctica, este artículo rige plazo. Excepto pacto en contrario, se entiende que el contrato de agencia se celebra por tiempo indeterminado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazoarticulo 1491'], segments: [], amendments: [] },
  { id: 'ccyc-art-1492', lawId: 'codigo-civil-comercial', number: '1492', order: 1492, title: "Preaviso", text: "Preaviso. En los contratos de agencia por tiempo indeterminado, cualquiera de las partes puede ponerle fin con un preaviso. El plazo del preaviso debe ser de un mes por cada año de vigencia del contrato. El final del plazo de preaviso debe coincidir con el final del mes calendario en el que aquél opera. Las disposiciones del presente artículo se aplican a los contratos de duración limitada transformados en contratos de duración ilimitada, a cuyo fin en el cálculo del plazo de preaviso debe computarse la duración limitada que le precede. Las partes pueden prever los plazos de preaviso superiores a los establecidos en este artículo.", plainLanguageExplanation: "Establece el régimen de preaviso. En los contratos de agencia por tiempo indeterminado, cualquiera de las partes puede ponerle fin con un preaviso.", practicalEffects: ['En la práctica, este artículo rige preaviso. En los contratos de agencia por tiempo indeterminado, cualquiera de las partes puede ponerle fin con un preaviso.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['preavisoarticulo 1492'], segments: [], amendments: [] },
  { id: 'ccyc-art-1493', lawId: 'codigo-civil-comercial', number: '1493', order: 1493, title: "Omisión de preaviso", text: "Omisión de preaviso. En los casos del artículo 1492, la omisión del preaviso, otorga a la otra parte derecho a la indemnización por las ganancias dejadas de percibir en el período.", plainLanguageExplanation: "Establece el régimen de omisión de preaviso. En los casos del artículo 1492, la omisión del preaviso, otorga a la otra parte derecho a la indemnización por las ganancias dejadas de percibir en el período.", practicalEffects: ['En la práctica, este artículo rige omisión de preaviso. En los casos del artículo 1492, la omisión del preaviso, otorga a la otra parte derecho a la indemnización por las ganancias dejadas de percibir en el'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['omisin', 'preaviso', 'articulo 1493'], segments: [], amendments: [] },
  { id: 'ccyc-art-1494', lawId: 'codigo-civil-comercial', number: '1494', order: 1494, title: "Resolución", text: "Resolución. Otras causales. El contrato de agencia se resuelve por: a) muerte o incapacidad del agente; b) disolución de la persona jurídica que celebra el contrato, que no deriva de fusión o escisión; c) quiebra firme de cualquiera de las partes; d) vencimiento del plazo; e) incumplimiento grave o reiterado de las obligaciones de una de las partes, de forma de poner razonablemente en duda la posibilidad o la intención del incumplidor de atender con exactitud las obligaciones sucesivas; f) disminución significativa del volumen de negocios del agente.", plainLanguageExplanation: "Establece el régimen de resolución. Otras causales.", practicalEffects: ['En la práctica, este artículo rige resolución. Otras causales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resolucinarticulo 1494'], segments: [], amendments: [] },
  { id: 'ccyc-art-1495', lawId: 'codigo-civil-comercial', number: '1495', order: 1495, title: "Manera en que opera la resolución", text: "Manera en que opera la resolución. En los casos previstos en los incisos a) a d) del artículo 1494, la resolución opera de pleno derecho, sin necesidad de preaviso ni declaración de la otra parte, sin perjuicio de lo dispuesto por el artículo 1492 para el supuesto de tiempo indeterminado. En el caso del inciso e) del artículo 1494, cada parte puede resolver directamente el contrato. En el caso del inciso f) del artículo 1494, se aplica el artículo 1492, excepto que el agente disminuya su volumen de negocios durante dos ejercicios consecutivos, en cuyo caso el plazo de preaviso no debe exceder de dos meses, cualesquiera haya sido la duración del contrato, aun cuando el contrato sea de plazo determinado.", plainLanguageExplanation: "Establece el régimen de manera en que opera la resolución. En los casos previstos en los incisos a) a d) del artículo 1494, la resolución opera de pleno derecho, sin necesidad de preaviso ni declaración de la otra parte, sin perjuicio de lo dispuesto por el artículo 1492 para el supuesto de tiempo indeterminado.", practicalEffects: ['En la práctica, este artículo rige manera en que opera la resolución. En los casos previstos en los incisos a) a d) del artículo 1494, la resolución opera de pleno derecho, sin necesidad de preaviso ni declaración de la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['manera', 'opera', 'resolucin', 'articulo 1495'], segments: [], amendments: [] },
  { id: 'ccyc-art-1496', lawId: 'codigo-civil-comercial', number: '1496', order: 1496, title: "Fusión o escisión", text: "Fusión o escisión. El contrato se resuelve si la persona jurídica que ha celebrado el contrato se fusiona o se escinde y cualquiera de estas dos circunstancias causa un detrimento sustancial en la posición del agente. Se deben las indemnizaciones del artículo 1497 y, en su caso, las del artículo 1493.", plainLanguageExplanation: "Establece el régimen de fusión o escisión. El contrato se resuelve si la persona jurídica que ha celebrado el contrato se fusiona o se escinde y cualquiera de estas dos circunstancias causa un detrimento sustancial en la posición del agente.", practicalEffects: ['En la práctica, este artículo rige fusión o escisión. El contrato se resuelve si la persona jurídica que ha celebrado el contrato se fusiona o se escinde y cualquiera de estas dos circunstancias causa un detrimento sustancial en la posición del agente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fusin', 'escisin', 'articulo 1496'], segments: [], amendments: [] },
  { id: 'ccyc-art-1497', lawId: 'codigo-civil-comercial', number: '1497', order: 1497, title: "Compensación por clientela", text: "Compensación por clientela. Extinguido el contrato, sea por tiempo determinado o indeterminado, el agente que mediante su labor ha incrementado significativamente el giro de las operaciones del empresario, tiene derecho a una compensación si su actividad anterior puede continuar produciendo ventajas sustanciales a éste. En caso de muerte del agente ese derecho corresponde a sus herederos. A falta de acuerdo, la compensación debe ser fijada judicialmente y no puede exceder del importe equivalente a un año de remuneraciones, neto de gastos, promediándose el valor de las percibidas por el agente durante los últimos cinco años, o durante todo el período de duración del contrato, si éste es inferior. Esta compensación no impide al agente, en su caso, reclamar por los daños derivados de la ruptura por culpa del empresario.", plainLanguageExplanation: "Establece el régimen de compensación por clientela. Extinguido el contrato, sea por tiempo determinado o indeterminado, el agente que mediante su labor ha incrementado significativamente el giro de las operaciones del empresario, tiene derecho a una compensación si su actividad anterior puede continuar produciendo ventajas sustanciales a éste.", practicalEffects: ['En la práctica, este artículo rige compensación por clientela. Extinguido el contrato, sea por tiempo determinado o indeterminado, el agente que mediante su labor ha incrementado significativamente el giro de las'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['compensacin', 'clientela', 'articulo 1497'], segments: [], amendments: [] },
  { id: 'ccyc-art-1498', lawId: 'codigo-civil-comercial', number: '1498', order: 1498, title: "Compensación por clientela", text: "Compensación por clientela. Excepciones. No hay derecho a compensación si: a) el empresario pone fin al contrato por incumplimiento del agente; b) el agente pone fin al contrato, a menos que la terminación esté justificada por incumplimiento del empresario; o por la edad, invalidez o enfermedad del agente, que no permiten exigir razonablemente la continuidad de sus actividades. Esta facultad puede ser ejercida por ambas partes.", plainLanguageExplanation: "Establece el régimen de compensación por clientela. Excepciones.", practicalEffects: ['En la práctica, este artículo rige compensación por clientela. Excepciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['compensacin', 'clientela', 'articulo 1498'], segments: [], amendments: [] },
  { id: 'ccyc-art-1499', lawId: 'codigo-civil-comercial', number: '1499', order: 1499, title: "Cláusula de no competencia", text: "Cláusula de no competencia. Las partes pueden pactar cláusulas de no competencia del agente para después de la finalización del contrato, si éste prevé la exclusividad del agente en el ramo de negocios del empresario. Son válidas en tanto no excedan de un año y se apliquen a un territorio o grupo de personas que resulten razonables, habida cuenta de las circunstancias.", plainLanguageExplanation: "Establece el régimen de cláusula de no competencia. Las partes pueden pactar cláusulas de no competencia del agente para después de la finalización del contrato, si éste prevé la exclusividad del agente en el ramo de negocios del empresario.", practicalEffects: ['En la práctica, este artículo rige cláusula de no competencia. Las partes pueden pactar cláusulas de no competencia del agente para después de la finalización del contrato, si éste prevé la exclusividad del agente en el ramo de negocios del empresario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusula', 'competencia', 'articulo 1499'], segments: [], amendments: [] },
  { id: 'ccyc-art-1500', lawId: 'codigo-civil-comercial', number: '1500', order: 1500, title: "Subagencia", text: "Subagencia. El agente no puede, excepto consentimiento expreso del empresario, instituir subagentes. Las relaciones entre agente y subagente son regidas por este Capítulo. El agente responde solidariamente por la actuación del subagente, el que, sin embargo, no tiene vínculo directo con el empresario.", plainLanguageExplanation: "Establece el régimen de subagencia. El agente no puede, excepto consentimiento expreso del empresario, instituir subagentes.", practicalEffects: ['En la práctica, este artículo rige subagencia. El agente no puede, excepto consentimiento expreso del empresario, instituir subagentes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['subagenciaarticulo 1500'], segments: [], amendments: [] },
  { id: 'ccyc-art-1501', lawId: 'codigo-civil-comercial', number: '1501', order: 1501, title: "Casos excluidos", text: "Casos excluidos. Las normas de este Capítulo no se aplican a los agentes de bolsa o de mercados de valores, de futuros y opciones o derivados; a los productores o agentes de seguros; a los agentes financieros, o cambiarios, a los agentes marítimos o aeronáuticos y a los demás grupos regidos por leyes especiales en cuanto a las operaciones que efectúen. CAPITULO 18 Concesión", plainLanguageExplanation: "Establece el régimen de casos excluidos. Las normas de este Capítulo no se aplican a los agentes de bolsa o de mercados de valores, de futuros y opciones o derivados; a los productores o agentes de seguros; a los agentes financieros, o cambiarios, a los agentes marítimos o aeronáuticos y a los demás grupos regidos por l", practicalEffects: ['En la práctica, este artículo rige casos excluidos. Las normas de este Capítulo no se aplican a los agentes de bolsa o de mercados de valores, de futuros y opciones o derivados; a los productores o agen'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'excluidos', 'articulo 1501'], segments: [], amendments: [] },
  { id: 'ccyc-art-1502', lawId: 'codigo-civil-comercial', number: '1502', order: 1502, title: "Definición", text: "Definición. Hay contrato de concesión cuando el concesionario, que actúa en nombre y por cuenta propia frente a terceros, se obliga mediante una retribución a disponer de su organización empresaria para comercializar mercaderías provistas por el concedente, prestar los servicios y proveer los repuestos y accesorios según haya sido convenido.", plainLanguageExplanation: "Establece el régimen de definición. Hay contrato de concesión cuando el concesionario, que actúa en nombre y por cuenta propia frente a terceros, se obliga mediante una retribución a disponer de su organización empresaria para comercializar mercaderías provistas por el concedente, prestar los servicios y proveer lo", practicalEffects: ['En la práctica, este artículo rige definición. Hay contrato de concesión cuando el concesionario, que actúa en nombre y por cuenta propia frente a terceros, se obliga mediante una retribución a dis'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1502'], segments: [], amendments: [] },
  { id: 'ccyc-art-1503', lawId: 'codigo-civil-comercial', number: '1503', order: 1503, title: "Exclusividad", text: "Exclusividad. Mercaderías. Excepto pacto en contrario: a) la concesión es exclusiva para ambas partes en el territorio o zona de influencia determinados. El concedente no puede autorizar otra concesión en el mismo territorio o zona y el concesionario no puede, por sí o por interpósita persona, ejercer actos propios de la concesión fuera de esos límites o actuar en actividades competitivas; b) la concesión comprende todas las mercaderías fabricadas o provistas por el concedente, incluso los nuevos modelos.", plainLanguageExplanation: "Establece el régimen de exclusividad. Mercaderías.", practicalEffects: ['En la práctica, este artículo rige exclusividad. Mercaderías.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exclusividadarticulo 1503'], segments: [], amendments: [] },
  { id: 'ccyc-art-1504', lawId: 'codigo-civil-comercial', number: '1504', order: 1504, title: "Obligaciones del concedente", text: "Obligaciones del concedente. Son obligaciones del concedente: a) proveer al concesionario de una cantidad mínima de mercaderías que le permita atender adecuadamente las expectativas de venta en su territorio o zona, de acuerdo con las pautas de pago, de financiación y garantías previstas en el contrato. El contrato puede prever la determinación de objetivos de ventas, los que deben ser fijados y comunicados al concesionario de acuerdo con lo convenido; b) respetar el territorio o zona de influencia asignado en exclusividad al concesionario. Son válidos los pactos que, no obstante la exclusividad, reserva para el concedente cierto tipo de ventas directas o modalidades de ventas especiales; c) proveer al concesionario la información técnica y, en su caso, los manuales y la capacitación de personal necesarios para la explotación de la concesión; d) proveer durante un período razonable, en su caso, repuestos para los productos comercializados; e) permitir el uso de marcas, enseñas comerciales y demás elementos distintivos, en la medida necesaria para la explotación de la concesión y para la publicidad del concesionario dentro de su territorio o zona de influencia.", plainLanguageExplanation: "Establece el régimen de obligaciones del concedente. Son obligaciones del concedente: a) proveer al concesionario de una cantidad mínima de mercaderías que le permita atender adecuadamente las expectativas de venta en su territorio o zona, de acuerdo con las pautas de pago, de financiación y garantías previstas en el contrato.", practicalEffects: ['En la práctica, este artículo rige obligaciones del concedente. Son obligaciones del concedente: a) proveer al concesionario de una cantidad mínima de mercaderías que le permita atender adecuadamente las expectativ'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'concedente', 'articulo 1504'], segments: [], amendments: [] },
  { id: 'ccyc-art-1505', lawId: 'codigo-civil-comercial', number: '1505', order: 1505, title: "Obligaciones del concesionario", text: "Obligaciones del concesionario. Son obligaciones del concesionario: a) comprar exclusivamente al concedente las mercaderías y, en su caso, los repuestos objeto de la concesión, y mantener la existencia convenida de ellos o, en defecto de convenio, la cantidad suficiente para asegurar la continuidad de los negocios y la atención del público consumidor; b) respetar los límites geográficos de actuación y abstenerse de comercializar mercaderías fuera de ellos, directa o indirectamente por interpósita persona; c) disponer de los locales y demás instalaciones y equipos que resulten necesarios para el adecuado cumplimiento de su actividad; d) prestar los servicios de preentrega y mantenimiento de las mercaderías, en caso de haberlo así convenido; e) adoptar el sistema de ventas, de publicidad y de contabilidad que fije el concedente; f) capacitar a su personal de conformidad con las normas del concedente. Sin perjuicio de lo dispuesto en el inciso a) de este artículo, el concesionario puede vender mercaderías del mismo ramo que le hayan sido entregadas en parte de pago de las que comercialice por causa de la concesión, así como financiar unas y otras y vender, exponer o promocionar otras mercaderías o servicios que se autoricen por el contrato, aunque no sean accesorios de las mercaderías objeto de la concesión ni estén destinados a ella.", plainLanguageExplanation: "Establece el régimen de obligaciones del concesionario. Son obligaciones del concesionario: a) comprar exclusivamente al concedente las mercaderías y, en su caso, los repuestos objeto de la concesión, y mantener la existencia convenida de ellos o, en defecto de convenio, la cantidad suficiente para asegurar la continuidad de los negoc", practicalEffects: ['En la práctica, este artículo rige obligaciones del concesionario. Son obligaciones del concesionario: a) comprar exclusivamente al concedente las mercaderías y, en su caso, los repuestos objeto de la concesión, y man'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'concesionario', 'articulo 1505'], segments: [], amendments: [] },
  { id: 'ccyc-art-1506', lawId: 'codigo-civil-comercial', number: '1506', order: 1506, title: "Plazos", text: "Plazos. El plazo del contrato de concesión no puede ser inferior a cuatro años. Pactado un plazo menor o si el tiempo es indeterminado, se entiende convenido por cuatro años. Excepcionalmente, si el concedente provee al concesionario el uso de las instalaciones principales suficientes para su desempeño, puede preverse un plazo menor, no inferior a dos años. La continuación de la relación después de vencido el plazo determinado por el contrato o por la ley, sin especificarse antes el nuevo plazo, lo transforma en contrato por tiempo indeterminado.", plainLanguageExplanation: "Establece el régimen de plazos. El plazo del contrato de concesión no puede ser inferior a cuatro años.", practicalEffects: ['En la práctica, este artículo rige plazos. El plazo del contrato de concesión no puede ser inferior a cuatro años.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazosarticulo 1506'], segments: [], amendments: [] },
  { id: 'ccyc-art-1507', lawId: 'codigo-civil-comercial', number: '1507', order: 1507, title: "Retribución", text: "Retribución. Gastos. El concesionario tiene derecho a una retribución, que puede consistir en una comisión o un margen sobre el precio de las unidades vendidas por él a terceros o adquiridas al concedente, o también en cantidades fijas u otras formas convenidas con el concedente. Los gastos de explotación están a cargo del concesionario, excepto los necesarios para atender los servicios de preentrega o de garantía gratuita a la clientela, en su caso, que deben ser pagados por el concedente conforme a lo pactado.", plainLanguageExplanation: "Establece el régimen de retribución. Gastos.", practicalEffects: ['En la práctica, este artículo rige retribución. Gastos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retribucinarticulo 1507'], segments: [], amendments: [] },
  { id: 'ccyc-art-1508', lawId: 'codigo-civil-comercial', number: '1508', order: 1508, title: "Rescisión de contratos por tiempo indeterminado", text: "Rescisión de contratos por tiempo indeterminado. Si el contrato de concesión es por tiempo indeterminado: a) son aplicables los artículos 1492 y 1493; b) el concedente debe readquirir los productos y repuestos nuevos que el concesionario haya adquirido conforme con las obligaciones pactadas en el contrato y que tenga en existencia al fin del período de preaviso, a los precios ordinarios de venta a los concesionarios al tiempo del pago.", plainLanguageExplanation: "Establece el régimen de rescisión de contratos por tiempo indeterminado. Si el contrato de concesión es por tiempo indeterminado: a) son aplicables los artículos 1492 y 1493; b) el concedente debe readquirir los productos y repuestos nuevos que el concesionario haya adquirido conforme con las obligaciones pactadas en el contrato y que tenga en existen", practicalEffects: ['En la práctica, este artículo rige rescisión de contratos por tiempo indeterminado. Si el contrato de concesión es por tiempo indeterminado: a) son aplicables los artículos 1492 y 1493; b) el concedente debe readquirir los productos y'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rescisin', 'contratos', 'tiempo', 'indeterminado', 'articulo 1508'], segments: [], amendments: [] },
  { id: 'ccyc-art-1509', lawId: 'codigo-civil-comercial', number: '1509', order: 1509, title: "Resolución del contrato de concesión", text: "Resolución del contrato de concesión. Causales. Al contrato de concesión se aplica el artículo 1494.", plainLanguageExplanation: "Establece el régimen de resolución del contrato de concesión. Causales.", practicalEffects: ['En la práctica, este artículo rige resolución del contrato de concesión. Causales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['resolucin', 'contrato', 'concesin', 'articulo 1509'], segments: [], amendments: [] },
  { id: 'ccyc-art-1510', lawId: 'codigo-civil-comercial', number: '1510', order: 1510, title: "Subconcesionarios", text: "Subconcesionarios. Cesión del contrato. Excepto pacto en contrario, el concesionario no puede designar subconcesionarios, agentes o intermediarios de venta, ni cualquiera de las partes puede ceder el contrato.", plainLanguageExplanation: "Establece el régimen de subconcesionarios. Cesión del contrato.", practicalEffects: ['En la práctica, este artículo rige subconcesionarios. Cesión del contrato.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['subconcesionariosarticulo 1510'], segments: [], amendments: [] },
  { id: 'ccyc-art-1511', lawId: 'codigo-civil-comercial', number: '1511', order: 1511, title: "Aplicación a otros contratos", text: "Aplicación a otros contratos. Las normas de este Capítulo se aplican a: a) los contratos por los que se conceda la venta o comercialización de software o de procedimientos similares; b) los contratos de distribución, en cuanto sean pertinentes. CAPITULO 19 Franquicia", plainLanguageExplanation: "Establece el régimen de aplicación a otros contratos. Las normas de este Capítulo se aplican a: a) los contratos por los que se conceda la venta o comercialización de software o de procedimientos similares; b) los contratos de distribución, en cuanto sean pertinentes.", practicalEffects: ['En la práctica, este artículo rige aplicación a otros contratos. Las normas de este Capítulo se aplican a: a) los contratos por los que se conceda la venta o comercialización de software o de procedimientos similare'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacin', 'otros', 'contratos', 'articulo 1511'], segments: [], amendments: [] },
  { id: 'ccyc-art-1512', lawId: 'codigo-civil-comercial', number: '1512', order: 1512, title: "Concepto", text: "Concepto. Hay franquicia comercial cuando una parte, denominada franquiciante, otorga a otra, llamada franquiciado, el derecho a utilizar un sistema probado, destinado a comercializar determinados bienes o servicios bajo el nombre comercial, emblema o la marca del franquiciante, quien provee un conjunto de conocimientos técnicos y la prestación continua de asistencia técnica o comercial, contra una prestación directa o indirecta del franquiciado. El franquiciante debe ser titular exclusivo del conjunto de los derechos intelectuales, marcas, patentes, nombres comerciales, derechos de autor y demás comprendidos en el sistema bajo franquicia; o, en su caso, tener derecho a su utilización y transmisión al franquiciado en los términos del contrato. El franquiciante no puede tener participación accionaria de control directo o indirecto en el negocio del franquiciado.", plainLanguageExplanation: "Establece el régimen de concepto. Hay franquicia comercial cuando una parte, denominada franquiciante, otorga a otra, llamada franquiciado, el derecho a utilizar un sistema probado, destinado a comercializar determinados bienes o servicios bajo el nombre comercial, emblema o la marca del franquiciante, quien prov", practicalEffects: ['En la práctica, este artículo rige concepto. Hay franquicia comercial cuando una parte, denominada franquiciante, otorga a otra, llamada franquiciado, el derecho a utilizar un sistema probado, de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 1512'], segments: [], amendments: [] },
  { id: 'ccyc-art-1513', lawId: 'codigo-civil-comercial', number: '1513', order: 1513, title: "Definiciones", text: "Definiciones. A los fines de la interpretación del contrato se entiende que: a) franquicia mayorista es aquella en virtud de la cual el franquiciante otorga a una persona física o jurídica un territorio o ámbito de actuación Nacional o regional o provincial con derecho de nombrar subfranquiciados, el uso de sus marcas y sistema de franquicias bajo contraprestaciones específicas; b) franquicia de desarrollo es aquella en virtud de la cual el franquiciante otorga a un franquiciado denominado desarrollador el derecho a abrir múltiples negocios franquiciados bajo el sistema, método y marca del franquiciante en una región o en el país durante un término prolongado no menor a cinco años, y en el que todos los locales o negocios que se abren dependen o están controlados, en caso de que se constituyan como sociedades, por el desarrollador, sin que éste tenga el derecho de ceder su posición como tal o subfranquiciar, sin el consentimiento del franquiciante; c) sistema de negocios: es el conjunto de conocimientos prácticos y la experiencia acumulada por el franquiciante, no patentado, que ha sido debidamente probado, secreto, sustancial y transmisible. Es secreto cuando en su conjunto o la configuración de sus componentes no es generalmente conocida o fácilmente accesible. Es sustancial cuando la información que contiene es relevante para la venta o prestación de servicios y permite al franquiciado prestar sus servicios o vender los productos conforme con el sistema de negocios. Es transmisible cuando su descripción es suficiente para permitir al franquiciado desarrollar su negocio de conformidad a las pautas creadas o desarrolladas por el franquiciante.", plainLanguageExplanation: "Establece el régimen de definiciones. A los fines de la interpretación del contrato se entiende que: a) franquicia mayorista es aquella en virtud de la cual el franquiciante otorga a una persona física o jurídica un territorio o ámbito de actuación Nacional o regional o provincial con derecho de nombrar subfranquicia", practicalEffects: ['En la práctica, este artículo rige definiciones. A los fines de la interpretación del contrato se entiende que: a) franquicia mayorista es aquella en virtud de la cual el franquiciante otorga a una p'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicionesarticulo 1513'], segments: [], amendments: [] },
  { id: 'ccyc-art-1514', lawId: 'codigo-civil-comercial', number: '1514', order: 1514, title: "Obligaciones del franquiciante", text: "Obligaciones del franquiciante. Son obligaciones del franquiciante: a) proporcionar, con antelación a la firma del contrato, información económica y financiera sobre la evolución de dos años de unidades similares a la ofrecida en franquicia, que hayan operado un tiempo suficiente, en el país o en el extranjero; b) comunicar al franquiciado el conjunto de conocimientos técnicos, aun cuando no estén patentados, derivados de la experiencia del franquiciante y comprobados por éste como aptos para producir los efectos del sistema franquiciado; c) entregar al franquiciado un manual de operaciones con las especificaciones útiles para desarrollar la actividad prevista en el contrato; d) proveer asistencia técnica para la mejor operatividad de la franquicia durante la vigencia del contrato; e) si la franquicia comprende la provisión de bienes o servicios a cargo del franquiciante o de terceros designados por él, asegurar esa provisión en cantidades adecuadas y a precios razonables, según usos y costumbres comerciales locales o internacionales; f) defender y proteger el uso por el franquiciado, en las condiciones del contrato, de los derechos referidos en el artículo 1512, sin perjuicio de que: i) en las franquicias internacionales esa defensa está contractualmente a cargo del franquiciado, a cuyo efecto debe ser especialmente apoderado sin perjuicio de la obligación del franquiciante de poner a disposición del franquiciado, en tiempo propio, la documentación y demás elementos necesarios para ese cometido; ii) en cualquier caso, el franquiciado está facultado para intervenir como interesado coadyuvante, en defensa de tales derechos, en las instancias administrativas o judiciales correspondientes, por las vías admitidas por la ley procesal, y en la medida que ésta lo permita.", plainLanguageExplanation: "Establece el régimen de obligaciones del franquiciante. Son obligaciones del franquiciante: a) proporcionar, con antelación a la firma del contrato, información económica y financiera sobre la evolución de dos años de unidades similares a la ofrecida en franquicia, que hayan operado un tiempo suficiente, en el país o en el extranjero;", practicalEffects: ['En la práctica, este artículo rige obligaciones del franquiciante. Son obligaciones del franquiciante: a) proporcionar, con antelación a la firma del contrato, información económica y financiera sobre la evolución de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'franquiciante', 'articulo 1514'], segments: [], amendments: [] },
  { id: 'ccyc-art-1515', lawId: 'codigo-civil-comercial', number: '1515', order: 1515, title: "Obligaciones del franquiciado", text: "Obligaciones del franquiciado. Son obligaciones mínimas del franquiciado: a) desarrollar efectivamente la actividad comprendida en la franquicia, cumplir las especificaciones del manual de operaciones y las que el franquiciante le comunique en cumplimiento de su deber de asistencia técnica; b) proporcionar las informaciones que razonablemente requiera el franquiciante para el conocimiento del desarrollo de la actividad y facilitar las inspecciones que se hayan pactado o que sean adecuadas al objeto de la franquicia; c) abstenerse de actos que puedan poner en riesgo la identificación o el prestigio del sistema de franquicia que integra o de los derechos mencionados en el artículo 1512, segundo párrafo, y cooperar, en su caso, en la protección de esos derechos; d) mantener la confidencialidad de la información reservada que integra el conjunto de conocimientos técnicos transmitidos y asegurar esa confidencialidad respecto de las personas, dependientes o no, a las que deban comunicarse para el desarrollo de las actividades. Esta obligación subsiste después de la expiración del contrato; e) cumplir con las contraprestaciones comprometidas, entre las que pueden pactarse contribuciones para el desarrollo del mercado o de las tecnologías vinculadas a la franquicia.", plainLanguageExplanation: "Establece el régimen de obligaciones del franquiciado. Son obligaciones mínimas del franquiciado: a) desarrollar efectivamente la actividad comprendida en la franquicia, cumplir las especificaciones del manual de operaciones y las que el franquiciante le comunique en cumplimiento de su deber de asistencia técnica; b) proporcionar las", practicalEffects: ['En la práctica, este artículo rige obligaciones del franquiciado. Son obligaciones mínimas del franquiciado: a) desarrollar efectivamente la actividad comprendida en la franquicia, cumplir las especificaciones del ma'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'franquiciado', 'articulo 1515'], segments: [], amendments: [] },
  { id: 'ccyc-art-1516', lawId: 'codigo-civil-comercial', number: '1516', order: 1516, title: "Plazo", text: "Plazo. Es aplicable el artículo 1506, primer párrafo. Sin embargo, un plazo inferior puede ser pactado si se corresponde con situaciones especiales como ferias o congresos, actividades desarrolladas dentro de predios o emprendimientos que tienen prevista una duración inferior, o similares. Al vencimiento del plazo, el contrato se entiende prorrogado tácitamente por plazos sucesivos de un año, excepto expresa denuncia de una de las partes antes de cada vencimiento con treinta días de antelación. A la segunda renovación, se transforma en contrato por tiempo indeterminado.", plainLanguageExplanation: "Establece el régimen de plazo. Es aplicable el artículo 1506, primer párrafo.", practicalEffects: ['En la práctica, este artículo rige plazo. Es aplicable el artículo 1506, primer párrafo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazoarticulo 1516'], segments: [], amendments: [] },
  { id: 'ccyc-art-1517', lawId: 'codigo-civil-comercial', number: '1517', order: 1517, title: "Cláusulas de exclusividad", text: "Cláusulas de exclusividad. Las franquicias son exclusivas para ambas partes. El franquiciante no puede autorizar otra unidad de franquicia en el mismo territorio, excepto con el consentimiento del franquiciado. El franquiciado debe desempeñarse en los locales indicados, dentro del territorio concedido o, en su defecto, en su zona de influencia, y no puede operar por sí o por interpósita persona unidades de franquicia o actividades que sean competitivas. Las partes pueden limitar o excluir la exclusividad.", plainLanguageExplanation: "Establece el régimen de cláusulas de exclusividad. Las franquicias son exclusivas para ambas partes.", practicalEffects: ['En la práctica, este artículo rige cláusulas de exclusividad. Las franquicias son exclusivas para ambas partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusulas', 'exclusividad', 'articulo 1517'], segments: [], amendments: [] },
  { id: 'ccyc-art-1518', lawId: 'codigo-civil-comercial', number: '1518', order: 1518, title: "Otras cláusulas", text: "Otras cláusulas. Excepto pacto en contrario: a) el franquiciado no puede ceder su posición contractual ni los derechos que emergen del contrato mientras está vigente, excepto los de contenido dinerario. Esta disposición no se aplica en los contratos de franquicia mayorista destinados a que el franquiciado otorgue a su vez subfranquicias, a esos efectos. En tales supuestos, debe contar con la autorización previa del franquiciante para otorgar subfranquicias en las condiciones que pacten entre el franquiciante y el franquiciado principal; b) el franquiciante no puede comercializar directamente con los terceros, mercaderías o servicios comprendidos en la franquicia dentro del territorio o zona de influencia del franquiciado; c) el derecho a la clientela corresponde al franquiciante. El franquiciado no puede mudar la ubicación de sus locales de atención o fabricación.", plainLanguageExplanation: "Establece el régimen de otras cláusulas. Excepto pacto en contrario: a) el franquiciado no puede ceder su posición contractual ni los derechos que emergen del contrato mientras está vigente, excepto los de contenido dinerario.", practicalEffects: ['En la práctica, este artículo rige otras cláusulas. Excepto pacto en contrario: a) el franquiciado no puede ceder su posición contractual ni los derechos que emergen del contrato mientras está vigente, excepto los de contenido dinerario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['otras', 'clusulas', 'articulo 1518'], segments: [], amendments: [] },
  { id: 'ccyc-art-1519', lawId: 'codigo-civil-comercial', number: '1519', order: 1519, title: "Cláusulas nulas", text: "Cláusulas nulas. No son válidas las cláusulas que prohíban al franquiciado: a) cuestionar justificadamente los derechos del franquiciante mencionado en el artículo 1512, segundo párrafo; b) adquirir mercaderías comprendidas en la franquicia de otros franquiciados dentro del país, siempre que éstos respondan a las calidades y características contractuales; c) reunirse o establecer vínculos no económicos con otros franquiciados.", plainLanguageExplanation: "Establece el régimen de cláusulas nulas. No son válidas las cláusulas que prohíban al franquiciado: a) cuestionar justificadamente los derechos del franquiciante mencionado en el artículo 1512, segundo párrafo; b) adquirir mercaderías comprendidas en la franquicia de otros franquiciados dentro del país, siempre que ésto", practicalEffects: ['En la práctica, este artículo rige cláusulas nulas. No son válidas las cláusulas que prohíban al franquiciado: a) cuestionar justificadamente los derechos del franquiciante mencionado en el artículo 151'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusulas', 'nulas', 'articulo 1519'], segments: [], amendments: [] },
  { id: 'ccyc-art-1520', lawId: 'codigo-civil-comercial', number: '1520', order: 1520, title: "Responsabilidad", text: "Responsabilidad. Las partes del contrato son independientes, y no existe relación laboral entre ellas. En consecuencia: a) el franquiciante no responde por las obligaciones del franquiciado, excepto disposición legal expresa en contrario; b) los dependientes del franquiciado no tienen relación jurídica laboral con el franquiciante, sin perjuicio de la aplicación de las normas sobre fraude laboral; c) el franquiciante no responde ante el franquiciado por la rentabilidad del sistema otorgado en franquicia. El franquiciado debe indicar claramente su calidad de persona independiente en sus facturas, contratos y demás documentos comerciales; esta obligación no debe interferir en la identidad común de la red franquiciada, en particular en sus nombres o rótulos comunes y en la presentación uniforme de sus locales, mercaderías o medios de transporte.", plainLanguageExplanation: "Establece el régimen de responsabilidad. Las partes del contrato son independientes, y no existe relación laboral entre ellas.", practicalEffects: ['En la práctica, este artículo rige responsabilidad. Las partes del contrato son independientes, y no existe relación laboral entre ellas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 1520'], segments: [], amendments: [] },
  { id: 'ccyc-art-1521', lawId: 'codigo-civil-comercial', number: '1521', order: 1521, title: "Responsabilidad por defectos en el sistema", text: "Responsabilidad por defectos en el sistema. El franquiciante responde por los defectos de diseño del sistema, que causan daños probados al franquiciado, no ocasionados por la negligencia grave o el dolo del franquiciado.", plainLanguageExplanation: "Establece el régimen de responsabilidad por defectos en el sistema. El franquiciante responde por los defectos de diseño del sistema, que causan daños probados al franquiciado, no ocasionados por la negligencia grave o el dolo del franquiciado.", practicalEffects: ['En la práctica, este artículo rige responsabilidad por defectos en el sistema. El franquiciante responde por los defectos de diseño del sistema, que causan daños probados al franquiciado, no ocasionados por la negligencia grave o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'defectos', 'sistema', 'articulo 1521'], segments: [], amendments: [] },
  { id: 'ccyc-art-1522', lawId: 'codigo-civil-comercial', number: '1522', order: 1522, title: "Extinción del contrato", text: "Extinción del contrato. La extinción del contrato de franquicia se rige por las siguientes reglas: a) el contrato se extingue por la muerte o incapacidad de cualquiera de las partes; b) el contrato no puede ser extinguido sin justa causa dentro del plazo de su vigencia original, pactado entre las partes. Se aplican los artículos 1084 y siguientes; c) los contratos con un plazo menor de tres años justificado por razones especiales según el artículo 1516, quedan extinguidos de pleno derecho al vencimiento del plazo; d) cualquiera sea el plazo de vigencia del contrato, la parte que desea concluirlo a la expiración del plazo original o de cualquiera de sus prórrogas, debe preavisar a la otra con una anticipación no menor de un mes por cada año de duración, hasta un máximo de seis meses, contados desde su inicio hasta el vencimiento del plazo pertinente. En los contratos que se pactan por tiempo indeterminado, el preaviso debe darse de manera que la rescisión se produzca, cuando menos, al cumplirse el tercer año desde su concertación. En ningún caso se requiere invocación de justa causa. La falta de preaviso hace aplicable el artículo 1493. La cláusula que impide la competencia del franquiciado con la comercialización de productos o servicios propios o de terceros después de extinguido el contrato por cualquier causa, es válida hasta el plazo máximo de un año y dentro de un territorio razonable habida cuenta de las circunstancias.", plainLanguageExplanation: "Establece el régimen de extinción del contrato. La extinción del contrato de franquicia se rige por las siguientes reglas: a) el contrato se extingue por la muerte o incapacidad de cualquiera de las partes; b) el contrato no puede ser extinguido sin justa causa dentro del plazo de su vigencia original, pactado entre las partes.", practicalEffects: ['En la práctica, este artículo rige extinción del contrato. La extinción del contrato de franquicia se rige por las siguientes reglas: a) el contrato se extingue por la muerte o incapacidad de cualquiera de las'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'contrato', 'articulo 1522'], segments: [], amendments: [] },
  { id: 'ccyc-art-1523', lawId: 'codigo-civil-comercial', number: '1523', order: 1523, title: "Derecho de la competencia", text: "Derecho de la competencia. El contrato de franquicia, por sí mismo, no debe ser considerado un pacto que limite, restrinja o distorsione la competencia.", plainLanguageExplanation: "Establece el régimen de derecho de la competencia. El contrato de franquicia, por sí mismo, no debe ser considerado un pacto que limite, restrinja o distorsione la competencia.", practicalEffects: ['En la práctica, este artículo rige derecho de la competencia. El contrato de franquicia, por sí mismo, no debe ser considerado un pacto que limite, restrinja o distorsione la competencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'competencia', 'articulo 1523'], segments: [], amendments: [] },
  { id: 'ccyc-art-1524', lawId: 'codigo-civil-comercial', number: '1524', order: 1524, title: "Casos comprendidos", text: "Casos comprendidos. Las disposiciones de este Capítulo se aplican, en cuanto sean compatibles, a las franquicias industriales y a las relaciones entre franquiciante y franquiciado principal y entre éste y cada uno de sus subfranquiciados. CAPITULO 20 Mutuo", plainLanguageExplanation: "Establece el régimen de casos comprendidos. Las disposiciones de este Capítulo se aplican, en cuanto sean compatibles, a las franquicias industriales y a las relaciones entre franquiciante y franquiciado principal y entre éste y cada uno de sus subfranquiciados.", practicalEffects: ['En la práctica, este artículo rige casos comprendidos. Las disposiciones de este Capítulo se aplican, en cuanto sean compatibles, a las franquicias industriales y a las relaciones entre franquiciante y fra'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'comprendidos', 'articulo 1524'], segments: [], amendments: [] },
  { id: 'ccyc-art-1525', lawId: 'codigo-civil-comercial', number: '1525', order: 1525, title: "Concepto", text: "Concepto. Hay contrato de mutuo cuando el mutuante se compromete a entregar al mutuario en propiedad, una determinada cantidad de cosas fungibles, y éste se obliga a devolver igual cantidad de cosas de la misma calidad y especie.", plainLanguageExplanation: "Establece el régimen de concepto. Hay contrato de mutuo cuando el mutuante se compromete a entregar al mutuario en propiedad, una determinada cantidad de cosas fungibles, y éste se obliga a devolver igual cantidad de cosas de la misma calidad y especie.", practicalEffects: ['En la práctica, este artículo rige concepto. Hay contrato de mutuo cuando el mutuante se compromete a entregar al mutuario en propiedad, una determinada cantidad de cosas fungibles, y éste se obl'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 1525'], segments: [], amendments: [] },
  { id: 'ccyc-art-1526', lawId: 'codigo-civil-comercial', number: '1526', order: 1526, title: "Obligación del mutuante", text: "Obligación del mutuante. El mutuante puede no entregar la cantidad prometida si, con posterioridad al contrato, un cambio en la situación del mutuario hace incierta la restitución. Excepto este supuesto, si el mutuante no entrega la cantidad prometida en el plazo pactado o, en su defecto, ante el simple requerimiento, el mutuario puede exigir el cumplimiento o la resolución del contrato.", plainLanguageExplanation: "Establece el régimen de obligación del mutuante. El mutuante puede no entregar la cantidad prometida si, con posterioridad al contrato, un cambio en la situación del mutuario hace incierta la restitución.", practicalEffects: ['En la práctica, este artículo rige obligación del mutuante. El mutuante puede no entregar la cantidad prometida si, con posterioridad al contrato, un cambio en la situación del mutuario hace incierta la restitución.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'mutuante', 'articulo 1526'], segments: [], amendments: [] },
  { id: 'ccyc-art-1527', lawId: 'codigo-civil-comercial', number: '1527', order: 1527, title: "Onerosidad", text: "Onerosidad. El mutuo es oneroso, excepto pacto en contrario. Si el mutuo es en dinero, el mutuario debe los intereses compensatorios, que se deben pagar en la misma moneda prestada. Si el mutuo es de otro tipo de cosas fungibles, los intereses son liquidados en dinero, tomando en consideración el precio de la cantidad de cosas prestadas en el lugar en que debe efectuarse el pago de los accesorios, el día del comienzo del período, excepto pacto en contrario. Los intereses se deben por trimestre vencido, o con cada amortización total o parcial de lo prestado que ocurra antes de un trimestre, excepto estipulación distinta. Si se ha pactado la gratuidad del mutuo, los intereses que haya pagado el mutuario voluntariamente son irrepetibles. El recibo de intereses por un período, sin condición ni reserva, hace presumir el pago de los anteriores.", plainLanguageExplanation: "Establece el régimen de onerosidad. El mutuo es oneroso, excepto pacto en contrario.", practicalEffects: ['En la práctica, este artículo rige onerosidad. El mutuo es oneroso, excepto pacto en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['onerosidadarticulo 1527'], segments: [], amendments: [] },
  { id: 'ccyc-art-1528', lawId: 'codigo-civil-comercial', number: '1528', order: 1528, title: "Plazo y lugar de restitución", text: "Plazo y lugar de restitución. Si nada se ha estipulado acerca del plazo y lugar para la restitución de lo prestado, el mutuario debe restituirlo dentro de los diez días de requerirlo el mutuante, excepto lo que surja de los usos, y en el lugar establecido en el artículo 874.", plainLanguageExplanation: "Establece el régimen de plazo y lugar de restitución. Si nada se ha estipulado acerca del plazo y lugar para la restitución de lo prestado, el mutuario debe restituirlo dentro de los diez días de requerirlo el mutuante, excepto lo que surja de los usos, y en el lugar establecido en el artículo 874.", practicalEffects: ['En la práctica, este artículo rige plazo y lugar de restitución. Si nada se ha estipulado acerca del plazo y lugar para la restitución de lo prestado, el mutuario debe restituirlo dentro de los diez días de requerir'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazo', 'lugar', 'restitucin', 'articulo 1528'], segments: [], amendments: [] },
  { id: 'ccyc-art-1529', lawId: 'codigo-civil-comercial', number: '1529', order: 1529, title: "Incumplimiento del mutuario", text: "Incumplimiento del mutuario. La falta de pago de los intereses o de cualquier amortización de capital da derecho al mutuante a resolver el contrato y a exigir la devolución de la totalidad de lo prestado, más sus intereses hasta la efectiva restitución. Si el mutuo es gratuito, después del incumplimiento, se deben intereses moratorios. Si el mutuo es oneroso a falta de convención sobre intereses moratorios, rige lo dispuesto para las obligaciones de dar sumas de dinero.", plainLanguageExplanation: "Establece el régimen de incumplimiento del mutuario. La falta de pago de los intereses o de cualquier amortización de capital da derecho al mutuante a resolver el contrato y a exigir la devolución de la totalidad de lo prestado, más sus intereses hasta la efectiva restitución.", practicalEffects: ['En la práctica, este artículo rige incumplimiento del mutuario. La falta de pago de los intereses o de cualquier amortización de capital da derecho al mutuante a resolver el contrato y a exigir la devolución de la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incumplimiento', 'mutuario', 'articulo 1529'], segments: [], amendments: [] },
  { id: 'ccyc-art-1530', lawId: 'codigo-civil-comercial', number: '1530', order: 1530, title: "Mala calidad o vicio de la cosa", text: "Mala calidad o vicio de la cosa. Si la cantidad prestada no es dinero, el mutuante responde por los daños causados por la mala calidad o el vicio de la cosa prestada; si el mutuo es gratuito, responde sólo si conoce la mala calidad o el vicio y no advierte al mutuario.", plainLanguageExplanation: "Establece el régimen de mala calidad o vicio de la cosa. Si la cantidad prestada no es dinero, el mutuante responde por los daños causados por la mala calidad o el vicio de la cosa prestada; si el mutuo es gratuito, responde sólo si conoce la mala calidad o el vicio y no advierte al mutuario.", practicalEffects: ['En la práctica, este artículo rige mala calidad o vicio de la cosa. Si la cantidad prestada no es dinero, el mutuante responde por los daños causados por la mala calidad o el vicio de la cosa prestada; si el mutuo es g'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mala', 'calidad', 'vicio', 'cosa', 'articulo 1530'], segments: [], amendments: [] },
  { id: 'ccyc-art-1531', lawId: 'codigo-civil-comercial', number: '1531', order: 1531, title: "Aplicación de las reglas de este Capítulo", text: "Aplicación de las reglas de este Capítulo. Las reglas de este Capítulo se aplican aunque el contrato de mutuo tenga cláusulas que establezcan que: a) la tasa de interés consiste en una parte o un porcentaje de las utilidades de un negocio o actividad, o se calcula a una tasa variable de acuerdo con ellos; b) el mutuante tiene derecho a percibir intereses o a recuperar su capital sólo de las utilidades o ingresos resultantes de un negocio o actividad, sin derecho a cobrarse de otros bienes del mutuario; c) el mutuario debe dar a los fondos un destino determinado.", plainLanguageExplanation: "Establece el régimen de aplicación de las reglas de este capítulo. Las reglas de este Capítulo se aplican aunque el contrato de mutuo tenga cláusulas que establezcan que: a) la tasa de interés consiste en una parte o un porcentaje de las utilidades de un negocio o actividad, o se calcula a una tasa variable de acuerdo con ellos; b) el mutuante t", practicalEffects: ['En la práctica, este artículo rige aplicación de las reglas de este capítulo. Las reglas de este Capítulo se aplican aunque el contrato de mutuo tenga cláusulas que establezcan que: a) la tasa de interés consiste en una parte o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacin', 'reglas', 'este', 'captulo', 'articulo 1531'], segments: [], amendments: [] },
  { id: 'ccyc-art-1532', lawId: 'codigo-civil-comercial', number: '1532', order: 1532, title: "Normas supletorias", text: "Normas supletorias. Se aplican al mutuo las disposiciones relativas a las obligaciones de dar sumas de dinero o de género, según sea el caso. CAPITULO 21 Comodato", plainLanguageExplanation: "Establece el régimen de normas supletorias. Se aplican al mutuo las disposiciones relativas a las obligaciones de dar sumas de dinero o de género, según sea el caso.", practicalEffects: ['En la práctica, este artículo rige normas supletorias. Se aplican al mutuo las disposiciones relativas a las obligaciones de dar sumas de dinero o de género, según sea el caso.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'supletorias', 'articulo 1532'], segments: [], amendments: [] },
  { id: 'ccyc-art-1533', lawId: 'codigo-civil-comercial', number: '1533', order: 1533, title: "Concepto", text: "Concepto. Hay comodato si una parte se obliga a entregar a otra una cosa no fungible, mueble o inmueble, para que se sirva gratuitamente de ella y restituya la misma cosa recibida.", plainLanguageExplanation: "Establece el régimen de concepto. Hay comodato si una parte se obliga a entregar a otra una cosa no fungible, mueble o inmueble, para que se sirva gratuitamente de ella y restituya la misma cosa recibida.", practicalEffects: ['En la práctica, este artículo rige concepto. Hay comodato si una parte se obliga a entregar a otra una cosa no fungible, mueble o inmueble, para que se sirva gratuitamente de ella y restituya la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 1533'], segments: [], amendments: [] },
  { id: 'ccyc-art-1534', lawId: 'codigo-civil-comercial', number: '1534', order: 1534, title: "Préstamo de cosas fungibles", text: "Préstamo de cosas fungibles. El préstamo de cosas fungibles sólo se rige por las normas del comodato si el comodatario se obliga a restituir las mismas cosas recibidas.", plainLanguageExplanation: "Establece el régimen de préstamo de cosas fungibles. El préstamo de cosas fungibles sólo se rige por las normas del comodato si el comodatario se obliga a restituir las mismas cosas recibidas.", practicalEffects: ['En la práctica, este artículo rige préstamo de cosas fungibles. El préstamo de cosas fungibles sólo se rige por las normas del comodato si el comodatario se obliga a restituir las mismas cosas recibidas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prstamo', 'cosas', 'fungibles', 'articulo 1534'], segments: [], amendments: [] },
  { id: 'ccyc-art-1535', lawId: 'codigo-civil-comercial', number: '1535', order: 1535, title: "Prohibiciones", text: "Prohibiciones. No pueden celebrar contrato de comodato: a) los tutores, curadores y apoyos, respecto de los bienes de las personas incapaces o con capacidad restringida, bajo su representación; b) los administradores de bienes ajenos, públicos o privados, respecto de los confiados a su gestión, excepto que tengan facultades expresas para ello.", plainLanguageExplanation: "Establece el régimen de prohibiciones. No pueden celebrar contrato de comodato: a) los tutores, curadores y apoyos, respecto de los bienes de las personas incapaces o con capacidad restringida, bajo su representación; b) los administradores de bienes ajenos, públicos o privados, respecto de los confiados a su gestión,", practicalEffects: ['En la práctica, este artículo rige prohibiciones. No pueden celebrar contrato de comodato: a) los tutores, curadores y apoyos, respecto de los bienes de las personas incapaces o con capacidad restring'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibicionesarticulo 1535'], segments: [], amendments: [] },
  { id: 'ccyc-art-1536', lawId: 'codigo-civil-comercial', number: '1536', order: 1536, title: "Obligaciones del comodatario", text: "Obligaciones del comodatario. Son obligaciones del comodatario: a) usar la cosa conforme al destino convenido. A falta de convención puede darle el destino que tenía al tiempo del contrato, el que se da a cosas análogas en el lugar donde la cosa se encuentra, o el que corresponde a su naturaleza; b) pagar los gastos ordinarios de la cosa y los realizados para servirse de ella; c) conservar la cosa con prudencia y diligencia; d) responder por la pérdida o deterioro de la cosa, incluso causados por caso fortuito, excepto que pruebe que habrían ocurrido igualmente si la cosa hubiera estado en poder del comodante; e) restituir la misma cosa con sus frutos y accesorios en el tiempo y lugar convenidos, A falta de convención, debe hacerlo cuando se satisface la finalidad para la cual se presta la cosa. Si la duración del contrato no está pactada ni surge de su finalidad, el comodante puede reclamar la restitución en cualquier momento. Si hay varios comodatarios, responden solidariamente.", plainLanguageExplanation: "Establece el régimen de obligaciones del comodatario. Son obligaciones del comodatario: a) usar la cosa conforme al destino convenido.", practicalEffects: ['En la práctica, este artículo rige obligaciones del comodatario. Son obligaciones del comodatario: a) usar la cosa conforme al destino convenido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'comodatario', 'articulo 1536'], segments: [], amendments: [] },
  { id: 'ccyc-art-1537', lawId: 'codigo-civil-comercial', number: '1537', order: 1537, title: "Cosa hurtada o perdida", text: "Cosa hurtada o perdida. El comodatario no puede negarse a restituir la cosa alegando que ella no pertenece al comodante, excepto que se trate de una cosa perdida por el dueño o hurtada a éste. Si el comodatario sabe que la cosa que se le ha entregado es hurtada o perdida, debe denunciarlo al dueño para que éste la reclame judicialmente en un plazo razonable. El comodatario es responsable de los daños que cause al dueño en caso de omitir la denuncia o si, pese a hacerla, restituye la cosa al comodante. El dueño no puede pretender del comodatario la devolución de la cosa sin consentimiento del comodante o sin resolución del juez.", plainLanguageExplanation: "Establece el régimen de cosa hurtada o perdida. El comodatario no puede negarse a restituir la cosa alegando que ella no pertenece al comodante, excepto que se trate de una cosa perdida por el dueño o hurtada a éste.", practicalEffects: ['En la práctica, este artículo rige cosa hurtada o perdida. El comodatario no puede negarse a restituir la cosa alegando que ella no pertenece al comodante, excepto que se trate de una cosa perdida por el dueño o hurtada a éste.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cosa', 'hurtada', 'perdida', 'articulo 1537'], segments: [], amendments: [] },
  { id: 'ccyc-art-1538', lawId: 'codigo-civil-comercial', number: '1538', order: 1538, title: "Gastos", text: "Gastos. El comodatario no puede solicitar el reembolso de los gastos ordinarios realizados para servirse de la cosa; tampoco puede retenerla por lo que le deba el comodante, aunque sea en razón de gastos extraordinarios de conservación.", plainLanguageExplanation: "Establece el régimen de gastos. El comodatario no puede solicitar el reembolso de los gastos ordinarios realizados para servirse de la cosa; tampoco puede retenerla por lo que le deba el comodante, aunque sea en razón de gastos extraordinarios de conservación.", practicalEffects: ['En la práctica, este artículo rige gastos. El comodatario no puede solicitar el reembolso de los gastos ordinarios realizados para servirse de la cosa; tampoco puede retenerla por lo que le deb'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gastosarticulo 1538'], segments: [], amendments: [] },
  { id: 'ccyc-art-1539', lawId: 'codigo-civil-comercial', number: '1539', order: 1539, title: "Restitución anticipada", text: "Restitución anticipada. El comodante puede exigir la restitución de la cosa antes del vencimiento del plazo: a) si la necesita en razón de una circunstancia imprevista y urgente; o b) si el comodatario la usa para un destino distinto al pactado, aunque no la deteriore.", plainLanguageExplanation: "Establece el régimen de restitución anticipada. El comodante puede exigir la restitución de la cosa antes del vencimiento del plazo: a) si la necesita en razón de una circunstancia imprevista y urgente; o b) si el comodatario la usa para un destino distinto al pactado, aunque no la deteriore.", practicalEffects: ['En la práctica, este artículo rige restitución anticipada. El comodante puede exigir la restitución de la cosa antes del vencimiento del plazo: a) si la necesita en razón de una circunstancia imprevista y urge'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['restitucin', 'anticipada', 'articulo 1539'], segments: [], amendments: [] },
  { id: 'ccyc-art-1540', lawId: 'codigo-civil-comercial', number: '1540', order: 1540, title: "Obligaciones del comodante", text: "Obligaciones del comodante. Son obligaciones del comodante: a) entregar la cosa en el tiempo y lugar convenidos; b) permitir el uso de la cosa durante el tiempo convenido; c) responder por los daños causados por los vicios de la cosa que oculta al comodatario; d) reembolsar los gastos de conservación extraordinarios que el comodatario hace, si éste los notifica previamente o si son urgentes.", plainLanguageExplanation: "Establece el régimen de obligaciones del comodante. Son obligaciones del comodante: a) entregar la cosa en el tiempo y lugar convenidos; b) permitir el uso de la cosa durante el tiempo convenido; c) responder por los daños causados por los vicios de la cosa que oculta al comodatario; d) reembolsar los gastos de conservación extrao", practicalEffects: ['En la práctica, este artículo rige obligaciones del comodante. Son obligaciones del comodante: a) entregar la cosa en el tiempo y lugar convenidos; b) permitir el uso de la cosa durante el tiempo convenido; c) res'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'comodante', 'articulo 1540'], segments: [], amendments: [] },
  { id: 'ccyc-art-1541', lawId: 'codigo-civil-comercial', number: '1541', order: 1541, title: "Extinción del comodato", text: "Extinción del comodato. El comodato se extingue: a) por destrucción de la cosa. No hay subrogación real, ni el comodante tiene obligación de prestar una cosa semejante; b) por vencimiento del plazo, se haya usado o no la cosa prestada; c) por voluntad unilateral del comodatario; d) por muerte del comodatario, excepto que se estipule lo contrario o que el comodato no haya sido celebrado exclusivamente en consideración a su persona. CAPITULO 22 Donación SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de extinción del comodato. El comodato se extingue: a) por destrucción de la cosa.", practicalEffects: ['En la práctica, este artículo rige extinción del comodato. El comodato se extingue: a) por destrucción de la cosa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'comodato', 'articulo 1541'], segments: [], amendments: [] },
  { id: 'ccyc-art-1542', lawId: 'codigo-civil-comercial', number: '1542', order: 1542, title: "Concepto", text: "Concepto. Hay donación cuando una parte se obliga a transferir gratuitamente una cosa a otra, y ésta lo acepta.", plainLanguageExplanation: "Establece el régimen de concepto. Hay donación cuando una parte se obliga a transferir gratuitamente una cosa a otra, y ésta lo acepta.", practicalEffects: ['En la práctica, este artículo rige concepto. Hay donación cuando una parte se obliga a transferir gratuitamente una cosa a otra, y ésta lo acepta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 1542'], segments: [], amendments: [] },
  { id: 'ccyc-art-1543', lawId: 'codigo-civil-comercial', number: '1543', order: 1543, title: "Aplicación subsidiaria", text: "Aplicación subsidiaria. Las normas de este Capítulo se aplican subsidiariamente a los demás actos jurídicos a título gratuito.", plainLanguageExplanation: "Establece el régimen de aplicación subsidiaria. Las normas de este Capítulo se aplican subsidiariamente a los demás actos jurídicos a título gratuito.", practicalEffects: ['En la práctica, este artículo rige aplicación subsidiaria. Las normas de este Capítulo se aplican subsidiariamente a los demás actos jurídicos a título gratuito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacin', 'subsidiaria', 'articulo 1543'], segments: [], amendments: [] },
  { id: 'ccyc-art-1544', lawId: 'codigo-civil-comercial', number: '1544', order: 1544, title: "Actos mixtos", text: "Actos mixtos. Los actos mixtos, en parte onerosos y en parte gratuitos, se rigen en cuanto a su forma por las disposiciones de este Capítulo; en cuanto a su contenido, por éstas en la parte gratuita y por las correspondientes a la naturaleza aparente del acto en la parte onerosa.", plainLanguageExplanation: "Establece el régimen de actos mixtos. Los actos mixtos, en parte onerosos y en parte gratuitos, se rigen en cuanto a su forma por las disposiciones de este Capítulo; en cuanto a su contenido, por éstas en la parte gratuita y por las correspondientes a la naturaleza aparente del acto en la parte onerosa.", practicalEffects: ['En la práctica, este artículo rige actos mixtos. Los actos mixtos, en parte onerosos y en parte gratuitos, se rigen en cuanto a su forma por las disposiciones de este Capítulo; en cuanto a su conteni'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'mixtos', 'articulo 1544'], segments: [], amendments: [] },
  { id: 'ccyc-art-1545', lawId: 'codigo-civil-comercial', number: '1545', order: 1545, title: "Aceptación", text: "Aceptación. La aceptación puede ser expresa o tácita, pero es de interpretación restrictiva y está sujeta a las reglas establecidas respecto a la forma de las donaciones. Debe producirse en vida del donante y del donatario.", plainLanguageExplanation: "Establece el régimen de aceptación. La aceptación puede ser expresa o tácita, pero es de interpretación restrictiva y está sujeta a las reglas establecidas respecto a la forma de las donaciones.", practicalEffects: ['En la práctica, este artículo rige aceptación. La aceptación puede ser expresa o tácita, pero es de interpretación restrictiva y está sujeta a las reglas establecidas respecto a la forma de las donaciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aceptacinarticulo 1545'], segments: [], amendments: [] },
  { id: 'ccyc-art-1546', lawId: 'codigo-civil-comercial', number: '1546', order: 1546, title: "Donación bajo condición", text: "Donación bajo condición. Están prohibidas las donaciones hechas bajo la condición suspensiva de producir efectos a partir del fallecimiento del donante.", plainLanguageExplanation: "Establece el régimen de donación bajo condición. Están prohibidas las donaciones hechas bajo la condición suspensiva de producir efectos a partir del fallecimiento del donante.", practicalEffects: ['En la práctica, este artículo rige donación bajo condición. Están prohibidas las donaciones hechas bajo la condición suspensiva de producir efectos a partir del fallecimiento del donante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['donacin', 'bajo', 'condicin', 'articulo 1546'], segments: [], amendments: [] },
  { id: 'ccyc-art-1547', lawId: 'codigo-civil-comercial', number: '1547', order: 1547, title: "Oferta conjunta", text: "Oferta conjunta. Si la donación es hecha a varias personas solidariamente, la aceptación de uno o algunos de los donatarios se aplica a la donación entera. Si la aceptación de unos se hace imposible por su muerte, o por revocación del donante respecto de ellos, la donación entera se debe aplicar a los que la aceptaron.", plainLanguageExplanation: "Establece el régimen de oferta conjunta. Si la donación es hecha a varias personas solidariamente, la aceptación de uno o algunos de los donatarios se aplica a la donación entera.", practicalEffects: ['En la práctica, este artículo rige oferta conjunta. Si la donación es hecha a varias personas solidariamente, la aceptación de uno o algunos de los donatarios se aplica a la donación entera.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oferta', 'conjunta', 'articulo 1547'], segments: [], amendments: [] },
  { id: 'ccyc-art-1548', lawId: 'codigo-civil-comercial', number: '1548', order: 1548, title: "Capacidad para donar", text: "Capacidad para donar. Pueden donar solamente las personas que tienen plena capacidad de disponer de sus bienes. Las personas menores emancipadas pueden hacerlo con la limitación del inciso b) del artículo 28.", plainLanguageExplanation: "Establece el régimen de capacidad para donar. Pueden donar solamente las personas que tienen plena capacidad de disponer de sus bienes.", practicalEffects: ['En la práctica, este artículo rige capacidad para donar. Pueden donar solamente las personas que tienen plena capacidad de disponer de sus bienes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capacidad', 'para', 'donar', 'articulo 1548'], segments: [], amendments: [] },
  { id: 'ccyc-art-1549', lawId: 'codigo-civil-comercial', number: '1549', order: 1549, title: "Capacidad para aceptar donaciones", text: "Capacidad para aceptar donaciones. Para aceptar donaciones se requiere ser capaz. Si la donación es a una persona incapaz, la aceptación debe ser hecha por su representante legal; si la donación del tercero o del representante es con cargo, se requiere autorización judicial.", plainLanguageExplanation: "Establece el régimen de capacidad para aceptar donaciones. Para aceptar donaciones se requiere ser capaz.", practicalEffects: ['En la práctica, este artículo rige capacidad para aceptar donaciones. Para aceptar donaciones se requiere ser capaz.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capacidad', 'para', 'aceptar', 'donaciones', 'articulo 1549'], segments: [], amendments: [] },
  { id: 'ccyc-art-1550', lawId: 'codigo-civil-comercial', number: '1550', order: 1550, title: "Tutores y curadores", text: "Tutores y curadores. Los tutores y curadores no pueden recibir donaciones de quienes han estado bajo su tutela o curatela antes de la rendición de cuentas y pago de cualquier suma que hayan quedado adeudándoles.", plainLanguageExplanation: "Establece el régimen de tutores y curadores. Los tutores y curadores no pueden recibir donaciones de quienes han estado bajo su tutela o curatela antes de la rendición de cuentas y pago de cualquier suma que hayan quedado adeudándoles.", practicalEffects: ['En la práctica, este artículo rige tutores y curadores. Los tutores y curadores no pueden recibir donaciones de quienes han estado bajo su tutela o curatela antes de la rendición de cuentas y pago de cualqu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tutores', 'curadores', 'articulo 1550'], segments: [], amendments: [] },
];
